const OFFSETS_ASCENDING = Object.keys(OFFSET_TO_TZ);

// Look up the catalog row for a TZ; falls back to a synthesized entry for offset-only zones
const getTZInfo = (tz) => {
  const found = TIMEZONES.find(t => t.tz === tz);
  if (found) return found;
  // Synthesize for offset-derived TZs not in our curated list
  return { tz, city: tz.replace(/_/g, ' ').split('/').pop(), country: '', flag: '🌐', offset: '', code: tz.split('/').pop() };
};

const formatIST = (date, opts = {}) => {
  const d = (date instanceof Date) ? date : new Date(date);
  if (isNaN(d.getTime())) return '';
  return d.toLocaleString('en-IN', { timeZone: APP_TZ, ...opts });
};
const formatInTZ = (date, tz, opts = {}) => {
  const d = (date instanceof Date) ? date : new Date(date);
  if (isNaN(d.getTime())) return '';
  return d.toLocaleString('en-IN', { timeZone: tz, ...opts });
};
const formatISTDate = (date) => formatIST(date, { weekday: 'long', day: 'numeric', month: 'long' });
const formatISTTime = (date) => formatIST(date, { hour: 'numeric', minute: '2-digit', hour12: true });
const formatISTShortDate = (date) => formatIST(date, { day: 'numeric', month: 'short' });

