// STORAGE ADAPTER — single source of truth for persistence
// Today: localStorage (per-browser, per-device, single user)
// Tomorrow: swap the bodies of load() / save() to call Supabase. The rest of
// the app never knows the difference.
// ============================================================================
const STORAGE_KEY = 'orbit.workspace.v4';
const STORAGE_CORRUPTED_KEY = 'orbit.workspace.v4.corrupted'; // forensic copy on migration failure
const PLATFORM_SESSION_EMAIL_STORAGE_KEY = 'orbit.platform.sessionEmail';
const CURRENT_SCHEMA_VERSION = 4; // bump when payload shape changes; add a migrator to MIGRATIONS below
const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://127.0.0.1:8787';
