let ORBIT_LAST_DB_COUNTS = ORBIT_DB_COUNTS_FALLBACK;

const normalizeSavedAt = (value) => {
  if (!value) return null;
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value.toISOString();
  if (typeof value === 'string' || typeof value === 'number') {
    const d = new Date(value);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }
  if (typeof value === 'object') {
    return normalizeSavedAt(value.savedAt || value.updatedAt || value.updated_at || value.createdAt || value.created_at);
  }
  return null;
};

const cloudSaveState = (wrapped) => {
  if (typeof window === 'undefined' || !wrapped?.data) return;
  fetch(`${API_BASE_URL}/state`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ state: wrapped }),
  })
    .then(async (response) => {
      const payload = await response.json().catch(() => ({}));
      if (!response.ok || !payload.ok) throw new Error(payload.error || 'Cloud save failed');
      const savedAt = normalizeSavedAt(payload.savedAt || payload.updatedAt || payload.updated_at || wrapped.savedAt);
      window.dispatchEvent(new CustomEvent('orbit:cloud-save', { detail: { ok: true, savedAt } }));
    })
    .catch((error) => {
      window.dispatchEvent(new CustomEvent('orbit:cloud-save', { detail: { ok: false, error: error.message } }));
    });
};

const cloudSaveDripFlow = async (campaign) => {
  if (!campaign?.id || !campaign?.flow?.nodes?.length) return { ok: false, skipped: true };
  const response = await fetch(`${API_BASE_URL}/drip-campaigns/${encodeURIComponent(campaign.id)}/flow`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ campaign, flow: campaign.flow }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || !payload.ok) throw new Error(payload.error || 'Drip flow save failed');
  window.dispatchEvent(new CustomEvent('orbit:cloud-save', { detail: { ok: true, savedAt: payload.savedAt } }));
  window.dispatchEvent(new CustomEvent('orbit:db-counts-refresh'));
  return payload;
};

const cloudLogDripEvent = async ({ campaignId, contactId, eventType, nodeKey, payload }) => {
  if (!campaignId || !eventType) return { ok: false, skipped: true };
  const response = await fetch(`${API_BASE_URL}/drip-events`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ campaignId, contactId, eventType, nodeKey, payload }),
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || !body.ok) throw new Error(body.error || 'Drip event save failed');
  window.dispatchEvent(new CustomEvent('orbit:db-counts-refresh'));
  return body;
};

