const cloudRunDripWorker = async ({ limit = 5 } = {}) => {
  const response = await fetch(`${API_BASE_URL}/drip-worker/run`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ limit }),
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || !body.ok) throw new Error(body.error || 'Drip worker failed');
  window.dispatchEvent(new CustomEvent('orbit:db-counts-refresh'));
  return body;
};

// ============================================================================
// MIGRATIONS — chain of pure functions that upgrade older payloads.
// Each entry's `from` produces the next version's shape. Chain is walked
// automatically until the payload is at CURRENT_SCHEMA_VERSION.
//
// Adding a new migration:
//   1. Bump CURRENT_SCHEMA_VERSION
//   2. Add { from: N, to: N+1, migrate: (oldData) => newData } below
//   3. Test by manually saving an old-shape payload and reloading
//
// Notes:
// - Migrations should be PURE (no side effects, return a NEW object)
// - On any migration throw, the corrupted payload is preserved under
//   STORAGE_CORRUPTED_KEY for manual forensic recovery
// - Currently empty because we've only ever shipped v=4. Framework is ready
//   for the first real version bump.
// ============================================================================
const MIGRATIONS = [
  // Example placeholder showing the shape; commented out because no migration is needed yet.
  // { from: 3, to: 4, migrate: (data) => ({ ...data, /* new fields */ }) },
];

const runMigrations = (data, fromVersion) => {
  let current = data;
  let v = fromVersion;
  while (v < CURRENT_SCHEMA_VERSION) {
    const step = MIGRATIONS.find(m => m.from === v);
    if (!step) {
      console.warn(`[storage] no migration path from v=${v} to v=${CURRENT_SCHEMA_VERSION} — treating as corrupted`);
      return null;
    }
    current = step.migrate(current);
    v = step.to;
  }
  return current;
};

const storage = {
  // Read everything as one object. Returns null if no saved data yet OR if migration fails.
  // On migration failure, the unreadable payload is preserved under the .corrupted key
  // so a tech-savvy user can manually recover.
  load() {
    try {
      const raw = typeof window === 'undefined' ? null : window.localStorage?.getItem(STORAGE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object') return null;
      const savedVersion = parsed.v;
      if (typeof savedVersion !== 'number') return null;

      // Current version → use as-is
      if (savedVersion === CURRENT_SCHEMA_VERSION) return parsed.data;

      // Newer version than this build supports? Don't touch it — refuse and preserve.
      // (User downgraded the app; we shouldn't downgrade their data.)
      if (savedVersion > CURRENT_SCHEMA_VERSION) {
        console.warn(`[storage] saved data is v=${savedVersion}, but this build only understands v=${CURRENT_SCHEMA_VERSION}. Preserving original; starting with seed.`);
        try { window.localStorage.setItem(STORAGE_CORRUPTED_KEY, raw); } catch (_) {}
        return null;
      }

      // Older version → run migration chain
      try {
        const migrated = runMigrations(parsed.data, savedVersion);
        if (!migrated) {
          // Migration couldn't complete; preserve original for forensics
          try { window.localStorage.setItem(STORAGE_CORRUPTED_KEY, raw); } catch (_) {}
          return null;
        }
        // Save the migrated payload back at the new version (so we don't re-migrate every load)
        const wrapped = { v: CURRENT_SCHEMA_VERSION, savedAt: new Date().toISOString(), data: migrated, migratedFrom: savedVersion };
        try { window.localStorage.setItem(STORAGE_KEY, JSON.stringify(wrapped)); } catch (_) {}
        console.info(`[storage] migrated payload from v=${savedVersion} to v=${CURRENT_SCHEMA_VERSION}`);
        return migrated;
      } catch (migrateErr) {
        console.warn('[storage] migration threw:', migrateErr);
        try { window.localStorage.setItem(STORAGE_CORRUPTED_KEY, raw); } catch (_) {}
        return null;
      }
    } catch (err) {
      console.warn('[storage] load failed:', err);
      return null;
    }
  },

  // Write everything as one object. Versioned so future schema changes don't crash old saves.
  save(payload) {
    try {
      if (typeof window === 'undefined' || !window.localStorage) return false;
      const wrapped = { v: CURRENT_SCHEMA_VERSION, savedAt: new Date().toISOString(), data: payload };
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(wrapped));
      window.dispatchEvent(new CustomEvent('orbit:auto-save', { detail: { savedAt: wrapped.savedAt, target: 'localStorage' } }));
      cloudSaveState(wrapped);
      return true;
    } catch (err) {
      console.warn('[storage] save failed:', err);
      return false;
    }
  },

  // Wipe everything. Next load() will return null, triggering a re-seed.
  clear() {
    try {
      if (typeof window === 'undefined' || !window.localStorage) return false;
      window.localStorage.removeItem(STORAGE_KEY);
      return true;
    } catch (err) {
      console.warn('[storage] clear failed:', err);
      return false;
    }
  },

  // Read the savedAt timestamp without parsing the whole payload — useful for UI display
  lastSavedAt() {
    try {
      const raw = typeof window !== 'undefined' && window.localStorage?.getItem(STORAGE_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      return normalizeSavedAt(parsed?.savedAt);
    } catch (err) {
      return null;
    }
  },
};


