const waDelayLabel = (mins) => {
  const before = mins < 0;
  const m = Math.abs(mins);
  let txt;
  if (m === 0) txt = 'immediately';
  else if (m % 1440 === 0) txt = `${m / 1440} day${m / 1440 !== 1 ? 's' : ''}`;
  else if (m % 60 === 0) txt = `${m / 60} hour${m / 60 !== 1 ? 's' : ''}`;
  else txt = `${m} min`;
  if (m === 0) return 'Immediately';
  return before ? `${txt} before` : `${txt} after`;
};

