// Live registry of ALL stages across ALL pipelines — synced from state so the
// crmStage(id) helper keeps working everywhere without passing a pipeline.
let CRM_ALL_STAGES = [...DEFAULT_PIPELINE_STAGES];
const setCrmStagesModule = (pipelines) => {
  const seen = {}; const out = [];
  (pipelines || []).forEach(p => (p.stages || []).forEach(s => { if (!seen[s.id]) { seen[s.id] = 1; out.push(s); } }));
  CRM_ALL_STAGES = out.length ? out : [...DEFAULT_PIPELINE_STAGES];
};
const crmStage = (id) => CRM_ALL_STAGES.find(s => s.id === id) || CRM_ALL_STAGES[0] || DEFAULT_PIPELINE_STAGES[0];

