const DRIP_MEDIA_TYPES = {
  image: { label: 'Image', icon: ImageIcon, tone: 'bg-sky-50 text-sky-700 ring-sky-200', hint: 'Poster, offer creative, product photo' },
  pdf: { label: 'PDF / Document', icon: FileText, tone: 'bg-rose-50 text-rose-700 ring-rose-200', hint: 'Brochure, guide, catalogue, proposal' },
  video: { label: 'Video', icon: Video, tone: 'bg-violet-50 text-violet-700 ring-violet-200', hint: 'Masterclass clip, demo video, walkthrough' },
  link: { label: 'Tracked Link', icon: Globe, tone: 'bg-emerald-50 text-emerald-700 ring-emerald-200', hint: 'Landing page, form, audit booking link' },
};

const normalizeDripMedia = (items = []) => (Array.isArray(items) ? items : [])
  .filter(item => item && String(item.url || '').trim())
  .map((item, index) => {
    const type = DRIP_MEDIA_TYPES[item.type] ? item.type : 'link';
    return {
      id: item.id || `media_${Date.now()}_${index}`,
      type,
      title: item.title || DRIP_MEDIA_TYPES[type].label,
      url: String(item.url || '').trim(),
      caption: item.caption || '',
      track: item.track !== false,
    };
  });

const dripMediaLabel = (items = []) => {
  const clean = normalizeDripMedia(items);
  if (!clean.length) return '';
  const counts = clean.reduce((acc, item) => ({ ...acc, [item.type]: (acc[item.type] || 0) + 1 }), {});
  return Object.entries(counts).map(([type, count]) => `${count} ${DRIP_MEDIA_TYPES[type]?.label || type}`).join(' · ');
};

const defaultDripFlow = (templates = []) => {
  const templateId = templates[0]?.id || '';
  return {
    version: 1,
    layout: 'horizontal',
    nodes: [
      { id: 'n-trigger', type: 'dripNode', position: { x: 40, y: 180 }, data: { kind: 'trigger', title: 'Contact enters audience', trigger: 'audience_match' } },
      { id: 'n-send-1', type: 'dripNode', position: { x: 310, y: 180 }, data: { kind: 'send_whatsapp', title: 'Send welcome WhatsApp', templateId } },
      { id: 'n-wait-1', type: 'dripNode', position: { x: 590, y: 180 }, data: { kind: 'wait', title: 'Wait 24 hours', mins: 1440 } },
      { id: 'n-condition-1', type: 'dripNode', position: { x: 860, y: 180 }, data: { kind: 'condition', title: 'Did they reply or click?', condition: 'clicked', withinHours: 24 } },
      { id: 'n-stage-yes', type: 'dripNode', position: { x: 1140, y: 80 }, data: { kind: 'update_stage', title: 'Move to MQL', toStage: 'mql' } },
      { id: 'n-reengage', type: 'dripNode', position: { x: 1140, y: 300 }, data: { kind: 'send_whatsapp', title: 'Send re-engagement', templateId } },
      { id: 'n-task', type: 'dripNode', position: { x: 1410, y: 80 }, data: { kind: 'create_task', title: 'Create sales follow-up', taskTitle: 'Follow up with engaged lead' } },
      { id: 'n-exit', type: 'dripNode', position: { x: 1410, y: 300 }, data: { kind: 'exit', title: 'End drip' } },
    ],
    edges: [
      { id: 'e-trigger-send', source: 'n-trigger', target: 'n-send-1', type: 'smoothstep' },
      { id: 'e-send-wait', source: 'n-send-1', target: 'n-wait-1', type: 'smoothstep' },
      { id: 'e-wait-condition', source: 'n-wait-1', target: 'n-condition-1', type: 'smoothstep' },
      { id: 'e-condition-yes', source: 'n-condition-1', sourceHandle: 'yes', target: 'n-stage-yes', label: 'yes', type: 'smoothstep', animated: true },
      { id: 'e-condition-no', source: 'n-condition-1', sourceHandle: 'no', target: 'n-reengage', label: 'no', type: 'smoothstep' },
      { id: 'e-stage-task', source: 'n-stage-yes', target: 'n-task', type: 'smoothstep' },
      { id: 'e-reengage-exit', source: 'n-reengage', target: 'n-exit', type: 'smoothstep' },
    ],
  };
};

