// ---------- AI Checklist Engine (rule-based mock for Phase 5) ----------
const AI_TEMPLATES = {
  payment:    ['Check pending invoice amount', 'Confirm due date', 'Send polite reminder via email', 'Call client if no response in 48 hrs', 'Update payment status in CRM', 'Share receipt confirmation', 'Close task'],
  followup:   ['Pull contact context from last interaction', 'Draft personalized message', 'Send via preferred channel', 'Schedule 48hr follow-up reminder', 'Log response in CRM', 'Move lead to next stage'],
  social:     ["Pick this week's content theme", 'Draft caption + hook', 'Design 3 visuals or 1 reel', 'Get internal review', 'Schedule the post', 'Reply to comments within 24 hrs'],
  report:     ['Pull data from source systems', 'Reconcile numbers', 'Build summary sheet', 'Add MoM/QoQ commentary', 'Share with stakeholders', 'Schedule review call'],
  onboarding: ['Confirm start date and role', 'Provision Google Workspace + Slack', 'Order laptop + accessories', 'Schedule day-1 orientation', 'Assign onboarding buddy', 'Send welcome email and policies'],
  proposal:   ['Confirm scope and pricing internally', 'Update proposal template', 'Add relevant case studies', 'Internal review with manager', 'Send to client stakeholders', 'Follow up in 48 hrs'],
  hiring:     ['Write job description', 'Post on 3 channels', 'Screen incoming applications', 'Schedule 1st-round interviews', 'Coordinate 2nd-round panel', 'Make offer + send paperwork'],
  meeting:    ['Define meeting objective', 'Draft agenda', 'Send invite with agenda', 'Prepare any prework', 'Run the meeting', 'Send minutes + action items'],
  generic:    ['Plan approach', 'Gather resources & inputs', 'Execute first pass', 'Internal review', 'Refine based on feedback', 'Wrap up and close'],
};
function suggestChecklist(title = '') {
  const t = title.toLowerCase();
  if (/payment|invoice|collect|due/.test(t))                return AI_TEMPLATES.payment;
  if (/follow.?up|lead|prospect/.test(t))                   return AI_TEMPLATES.followup;
  if (/social|post|reel|carousel|linkedin|instagram/.test(t)) return AI_TEMPLATES.social;
  if (/report|summary|p&l|review|metrics|month|quarter/.test(t)) return AI_TEMPLATES.report;
  if (/onboard|new hire|new joiner|joining/.test(t))        return AI_TEMPLATES.onboarding;
  if (/proposal|deck|sow|quote|pitch/.test(t))              return AI_TEMPLATES.proposal;
  if (/hir(e|ing)|interview|recruit|jd/.test(t))            return AI_TEMPLATES.hiring;
  if (/meeting|call|sync|standup|kickoff/.test(t))          return AI_TEMPLATES.meeting;
  return AI_TEMPLATES.generic;
}

