// ---------- Recurring scheduler engine (Phase 6) ----------
const WEEKDAYS = [
  { id: 'mon', label: 'M', full: 'Monday' },
  { id: 'tue', label: 'T', full: 'Tuesday' },
  { id: 'wed', label: 'W', full: 'Wednesday' },
  { id: 'thu', label: 'T', full: 'Thursday' },
  { id: 'fri', label: 'F', full: 'Friday' },
  { id: 'sat', label: 'S', full: 'Saturday' },
  { id: 'sun', label: 'S', full: 'Sunday' },
];
const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const CADENCES = [
  { id: 'daily',       label: 'Daily' },
  { id: 'weekly',      label: 'Weekly' },
  { id: 'fortnightly', label: 'Fortnightly' },
  { id: 'monthly',     label: 'Monthly' },
  { id: 'quarterly',   label: 'Quarterly' },
  { id: 'half',        label: 'Half-yearly' },
  { id: 'annually',    label: 'Annually' },
  { id: 'custom',      label: 'Custom' },
];
const ord = (n) => { const s=['th','st','nd','rd'], v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); };
function describeRule(rule) {
  if (!rule) return 'Not set';
  switch (rule.cadence) {
    case 'daily':       return 'Every day';
    case 'weekly':      return `Every week on ${(rule.days||[]).map(d => WEEKDAYS.find(w=>w.id===d)?.full?.slice(0,3)).filter(Boolean).join(', ') || '—'}`;
    case 'fortnightly': return `Twice a month on the ${(rule.dates||[]).map(ord).join(' & ') || '—'}`;
    case 'monthly':     return `Every month on the ${(rule.dates||[]).map(ord).join(', ') || '—'}`;
    case 'quarterly':   return `On the ${ord(rule.date||1)} of every quarter`;
    case 'half':        return `Twice a year (${(rule.cycles||[]).map(c => c?.month ? `${MONTHS[c.month-1]} ${c.date||1}` : '—').join(' & ')})`;
    case 'annually':    return `Every year on ${MONTHS[(rule.month||1)-1]} ${rule.date||1}`;
    case 'custom':      return `Every ${rule.every||1} ${rule.unit||'days'}`;
    default: return 'Not set';
  }
}

const RecurringScheduler = ({ rule, onChange }) => {
  const r = rule || { cadence: 'weekly', days: ['mon','wed','fri'], endType: 'never' };
  const set = (patch) => onChange({ ...r, ...patch });
  const toggleDate = (d) => {
    const cur = r.dates || [];
    if (cur.includes(d)) set({ dates: cur.filter(x => x !== d) });
    else if (r.cadence === 'fortnightly' && cur.length >= 2) set({ dates: [cur[1], d].sort((a,b)=>a-b) });
    else set({ dates: [...cur, d].sort((a,b)=>a-b) });
  };
  return (
    <div className="space-y-3 p-3 rounded-xl bg-violet-50/40 ring-1 ring-violet-100">
      <div className="flex flex-wrap gap-1">
        {CADENCES.map(c => (
          <button key={c.id} onClick={() => set({ cadence: c.id })}
            className={`px-2 py-1 rounded-md text-[11px] font-semibold ring-1 ring-inset transition ${r.cadence === c.id ? 'bg-violet-600 text-white ring-violet-600' : 'bg-white text-slate-600 ring-slate-200 hover:ring-slate-300'}`}>
            {c.label}
          </button>
        ))}
      </div>

      {r.cadence === 'daily' && <div className="text-[11px] text-slate-500 italic px-1">Generates once every day at the task start time.</div>}

      {r.cadence === 'weekly' && (
        <div className="flex gap-1">
          {WEEKDAYS.map(w => {
            const on = (r.days || []).includes(w.id);
            return (
              <button key={w.id} title={w.full} onClick={() => set({ days: on ? r.days.filter(d => d !== w.id) : [...(r.days||[]), w.id] })}
                className={`h-9 w-9 rounded-lg text-[13px] font-semibold ring-1 ring-inset ${on ? 'bg-violet-600 text-white ring-violet-600' : 'bg-white text-slate-500 ring-slate-200 hover:ring-slate-300'}`}>
                {w.label}
              </button>
            );
          })}
        </div>
      )}

      {(r.cadence === 'fortnightly' || r.cadence === 'monthly') && (
        <div>
          <div className="text-[11px] text-slate-500 mb-1.5">{r.cadence === 'fortnightly' ? 'Pick 2 dates of the month' : 'Pick one or more dates'}</div>
          <div className="grid grid-cols-7 gap-1">
            {Array.from({length:31}, (_,i)=>i+1).map(d => {
              const on = (r.dates||[]).includes(d);
              return (
                <button key={d} onClick={() => toggleDate(d)} className={`h-7 rounded text-[11px] font-semibold ${on ? 'bg-violet-600 text-white' : 'bg-white text-slate-700 ring-1 ring-slate-200 hover:bg-slate-50'}`}>{d}</button>
              );
            })}
          </div>
        </div>
      )}

      {r.cadence === 'quarterly' && (
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-[11px] text-slate-500">On the</span>
          <input type="number" min="1" max="31" value={r.date || 1} onChange={(e) => set({ date: Math.max(1, Math.min(31, parseInt(e.target.value)||1)) })} className="h-9 w-16 px-2 rounded-lg border border-slate-200 bg-white text-[13px] focus:outline-none focus:ring-2 focus:ring-indigo-500/30" />
          <span className="text-[11px] text-slate-500">of every quarter (Mar / Jun / Sep / Dec)</span>
        </div>
      )}

      {r.cadence === 'half' && (
        <div className="space-y-2">
          <div className="text-[11px] text-slate-500">Two cycles a year</div>
          {[0, 1].map(i => {
            const cycle = r.cycles?.[i] || { month: i*6+1, date: 1 };
            return (
              <div key={i} className="flex items-center gap-2 flex-wrap">
                <span className="text-[11px] text-slate-500 w-12">Cycle {i+1}</span>
                <SelectPill value={cycle.month} onChange={(v) => { const cs = [r.cycles?.[0] || {month:1,date:1}, r.cycles?.[1] || {month:7,date:1}]; cs[i] = {...cs[i], month: v}; set({ cycles: cs }); }}
                  options={MONTHS.map((m,j) => ({value: j+1, label: m}))} render={(v) => <span className="text-[13px]">{MONTHS[v-1]}</span>} />
                <span className="text-[11px] text-slate-500">on</span>
                <input type="number" min="1" max="31" value={cycle.date} onChange={(e) => { const cs = [r.cycles?.[0] || {month:1,date:1}, r.cycles?.[1] || {month:7,date:1}]; cs[i] = {...cs[i], date: Math.max(1, Math.min(31, parseInt(e.target.value)||1))}; set({ cycles: cs }); }} className="h-9 w-16 px-2 rounded-lg border border-slate-200 bg-white text-[13px]" />
              </div>
            );
          })}
        </div>
      )}

      {r.cadence === 'annually' && (
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-[11px] text-slate-500">On</span>
          <SelectPill value={r.month || 1} onChange={(v) => set({ month: v })} options={MONTHS.map((m,i) => ({value: i+1, label: m}))} render={(v) => <span className="text-[13px]">{MONTHS[v-1]}</span>} />
          <input type="number" min="1" max="31" value={r.date || 1} onChange={(e) => set({ date: Math.max(1, Math.min(31, parseInt(e.target.value)||1)) })} className="h-9 w-16 px-2 rounded-lg border border-slate-200 bg-white text-[13px]" />
        </div>
      )}

      {r.cadence === 'custom' && (
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-[11px] text-slate-500">Every</span>
          <input type="number" min="1" value={r.every || 1} onChange={(e) => set({ every: Math.max(1, parseInt(e.target.value)||1) })} className="h-9 w-16 px-2 rounded-lg border border-slate-200 bg-white text-[13px]" />
          <SelectPill value={r.unit || 'days'} onChange={(v) => set({ unit: v })} options={[{value:'days',label:'days'},{value:'weeks',label:'weeks'},{value:'months',label:'months'}]} render={(v) => <span className="text-[13px]">{v}</span>} />
        </div>
      )}

      <div className="flex items-center gap-2 flex-wrap pt-2 border-t border-violet-100">
        <span className="text-[11px] text-slate-500">Ends</span>
        <SelectPill value={r.endType || 'never'} onChange={(v) => set({ endType: v })} options={[{value:'never',label:'Never'},{value:'on',label:'On a date'},{value:'after',label:'After N times'}]}
          render={(v) => <span className="text-[13px]">{v === 'never' ? 'Never' : v === 'on' ? 'On date' : 'After N'}</span>} />
        {r.endType === 'on' && <input type="date" value={r.endDate || ''} onChange={(e) => set({ endDate: e.target.value })} className="h-9 px-2 rounded-lg border border-slate-200 bg-white text-[13px]" />}
        {r.endType === 'after' && (<><input type="number" min="1" value={r.endAfter || 10} onChange={(e) => set({ endAfter: Math.max(1, parseInt(e.target.value)||1) })} className="h-9 w-16 px-2 rounded-lg border border-slate-200 bg-white text-[13px]" /><span className="text-[11px] text-slate-500">times</span></>)}
      </div>

      <div className="inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-white ring-1 ring-violet-200 text-[11px] text-violet-700 font-semibold">
        <RotateCw className="h-3 w-3" />Generates: {describeRule(r)}
      </div>
    </div>
  );
};

