// ---------- Helpers ----------
const user = (id) => USERS.find(u => u.id === id);
const dept = (id) => DEPARTMENTS.find(d => d.id === id);

const indianWhatsAppNational = (value) => {
  const digits = String(value || '').replace(/\D/g, '');
  if (digits.length === 12 && digits.startsWith('91')) return digits.slice(2);
  if (digits.length === 11 && digits.startsWith('0')) return digits.slice(1);
  return digits;
};
const indianWhatsAppSendNumber = (value) => {
  const national = indianWhatsAppNational(value);
  return national.length === 10 ? `91${national}` : national;
};
const indianWhatsAppState = (value, required = false) => {
  const national = indianWhatsAppNational(value);
  if (!national) return { national, sendNumber: '', valid: !required, message: required ? 'Indian WhatsApp number is required' : 'Optional' };
  if (national.length < 10) return { national, sendNumber: national, valid: false, message: `Need ${10 - national.length} more digit${10 - national.length === 1 ? '' : 's'}` };
  if (national.length > 10) return { national, sendNumber: national, valid: false, message: `Remove ${national.length - 10} extra digit${national.length - 10 === 1 ? '' : 's'}` };
  return { national, sendNumber: `91${national}`, valid: true, message: 'Valid Indian WhatsApp number' };
};

const fileToBase64 = (file) => new Promise((resolve, reject) => {
  const reader = new FileReader();
  reader.onload = () => resolve(String(reader.result || '').split(',')[1] || '');
  reader.onerror = () => reject(reader.error || new Error('File read failed'));
  reader.readAsDataURL(file);
});
const readableFileSize = (size) => {
  const n = Number(size || 0);
  if (!n) return 'file';
  if (n < 1024 * 1024) return `${Math.ceil(n / 1024)} KB`;
  return `${(n / (1024 * 1024)).toFixed(n < 10 * 1024 * 1024 ? 1 : 0)} MB`;
};
const intranetAttachmentType = (mimeType = '') => {
  const mime = String(mimeType || '').toLowerCase();
  if (mime.startsWith('video/')) return 'video';
  if (mime.startsWith('audio/')) return 'voice_note';
  if (mime.startsWith('image/')) return 'image';
  return 'attachment';
};

