// Capacity helpers: derive daily capacity from weekly contract.
// Off-days: 5-day week = Sat + Sun off; 6-day = Sun off.
const dailyCapMinutes = (u) => {
  if (!u) return 480;
  const hpw = typeof u.hoursPerWeek === 'number' ? u.hoursPerWeek : 40;
  const dpw = typeof u.daysPerWeek === 'number' ? u.daysPerWeek : 5;
  if (dpw <= 0) return 0;
  return Math.round((hpw / dpw) * 60);
};
const isOffDay = (u, date) => {
  if (!u || !date) return false;
  const dpw = typeof u.daysPerWeek === 'number' ? u.daysPerWeek : 5;
  const dow = date.getDay(); // 0=Sun, 6=Sat
  if (dpw <= 5) return dow === 0 || dow === 6;
  if (dpw === 6) return dow === 0;
  return false;
};

// Lightweight markdown render: bullets (* ...), checkboxes ([x]/[ ]), headings (## ...), bold (**...**).
// Returns an array of React-renderable line objects for the caller to map.
const renderMarkdownLines = (text) => {
  if (!text) return [];
  const lines = String(text).split(/\r?\n/);
  return lines.map((raw, i) => {
    const line = raw;
    let kind = 'p', content = line, checked = false;
    const trimmed = line.trimStart();
    if (trimmed.startsWith('## ')) { kind = 'h2'; content = trimmed.slice(3); }
    else if (trimmed.startsWith('# ')) { kind = 'h1'; content = trimmed.slice(2); }
    else if (/^\[[xX ]\]\s/.test(trimmed)) {
      kind = 'task';
      checked = /^\[[xX]\]/.test(trimmed);
      content = trimmed.replace(/^\[[xX ]\]\s/, '');
    } else if (/^[*\-]\s/.test(trimmed)) {
      kind = 'li';
      content = trimmed.replace(/^[*\-]\s/, '');
    }
    // Inline bold **...** → split to spans
    const boldParts = content.split(/(\*\*[^*]+\*\*)/g).filter(Boolean).map(seg =>
      /^\*\*[^*]+\*\*$/.test(seg) ? { bold: true, text: seg.slice(2, -2) } : { bold: false, text: seg }
    );
    return { key: i, kind, parts: boldParts, checked };
  });
};

// Format minutes as "30m", "2h", "1d 4h", etc. 8h = 1 day.
const formatEstimate = (mins) => {
  if (!mins || mins <= 0) return '';
  if (mins < 60) return `${mins}m`;
  const h = mins / 60;
  if (h < 8) return Number.isInteger(h) ? `${h}h` : `${h.toFixed(1).replace(/\.0$/, '')}h`;
  const days = Math.floor(h / 8);
  const remH = Math.round(h - days * 8);
  return remH > 0 ? `${days}d ${remH}h` : `${days}d`;
};
