function actionsFor(task, role) {
  if (!task) return [];
  const a = [];
  switch (task.status) {
    case 'draft':
      a.push({ key: 'assign', label: 'Assign task', icon: ArrowUpRight, next: 'assigned', primary: true });
      break;
    case 'scheduled':
      a.push({ key: 'activate', label: 'Activate now', icon: ArrowUpRight, next: 'assigned', primary: true });
      a.push({ key: 'start',    label: 'Start task',   icon: Play,         next: 'in_progress' });
      break;
    case 'assigned':
      a.push({ key: 'start', label: 'Start task', icon: Play, next: 'in_progress', primary: true });
      break;
    case 'in_progress':
      a.push({ key: 'submit', label: 'Submit task', icon: Send,
               next: (task.reviewRequired || task.manager) ? 'pending' : 'completed', primary: true });
      break;
    case 'submitted':
    case 'pending':
      if (role === 'admin' || role === 'manager') {
        a.push({ key: 'approve', label: 'Approve',          icon: CheckCircle2, next: 'completed', primary: true });
        a.push({ key: 'revise',  label: 'Request revision', icon: RotateCcw,    next: 'revision' });
        a.push({ key: 'reject',  label: 'Reject',           icon: X,            next: 'cancelled', danger: true });
      } else {
        a.push({ key: 'recall', label: 'Recall submission', icon: RotateCcw, next: 'in_progress' });
      }
      break;
    case 'revision':
      a.push({ key: 'resubmit', label: 'Re-submit', icon: Send, next: 'pending', primary: true });
      break;
    case 'completed':
      a.push({ key: 'reopen', label: 'Re-open', icon: RotateCcw, next: 'in_progress' });
      break;
    case 'overdue':
      a.push({ key: 'resume', label: 'Resume', icon: Play, next: 'in_progress', primary: true });
      break;
  }
  return a;
}

