// ---------- Chart primitives (Phase 9) ----------
const Donut = ({ data, size = 140, thickness = 22 }) => {
  const total = data.reduce((s, d) => s + d.value, 0) || 1;
  const r = (size - thickness) / 2;
  const ri = r - thickness;
  const cx = size / 2, cy = size / 2;
  const polar = (rr, deg) => [cx + rr * Math.cos((deg-90)*Math.PI/180), cy + rr * Math.sin((deg-90)*Math.PI/180)];
  let acc = 0;
  const segs = data.map(d => { const start = (acc/total)*360; acc += d.value; return { ...d, start, end: (acc/total)*360 }; });
  const arcPath = (start, end) => {
    if (end - start >= 359.99) end = start + 359.99;
    const [x1,y1] = polar(r, start), [x2,y2] = polar(r, end);
    const [xi1,yi1] = polar(ri, start), [xi2,yi2] = polar(ri, end);
    const large = end - start > 180 ? 1 : 0;
    return `M ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2} L ${xi2} ${yi2} A ${ri} ${ri} 0 ${large} 0 ${xi1} ${yi1} Z`;
  };
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {segs.map((s, i) => <path key={i} d={arcPath(s.start, s.end)} fill={s.color} />)}
      <text x={cx} y={cy-2} textAnchor="middle" dominantBaseline="central" className="font-bold" fontSize="22" fill="#0f172a" style={{ fontVariantNumeric: 'tabular-nums' }}>{total}</text>
      <text x={cx} y={cy+14} textAnchor="middle" dominantBaseline="central" fontSize="10" fill="#64748b">total</text>
    </svg>
  );
};

const Sparkline = ({ data, width = 560, height = 140, color = '#6366f1' }) => {
  if (!data || data.length === 0) return null;
  const max = Math.max(...data, 1);
  const pad = 12;
  const w = width - pad * 2;
  const h = height - pad * 2;
  const pts = data.map((v, i) => [pad + (i / Math.max(1, data.length - 1)) * w, pad + h - (v / max) * h]);
  // smooth curve via simple cubic
  const smooth = pts.reduce((acc, p, i, arr) => {
    if (i === 0) return `M ${p[0]} ${p[1]}`;
    const prev = arr[i-1];
    const cpx = (prev[0] + p[0]) / 2;
    return acc + ` C ${cpx} ${prev[1]}, ${cpx} ${p[1]}, ${p[0]} ${p[1]}`;
  }, '');
  const area = smooth + ` L ${pts[pts.length-1][0]} ${height - pad} L ${pts[0][0]} ${height - pad} Z`;
  const gid = 'spk' + color.replace('#','');
  return (
    <svg width="100%" height={height} viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      <defs>
        <linearGradient id={gid} x1="0" x2="0" y1="0" y2="1">
          <stop offset="0%"   stopColor={color} stopOpacity="0.25" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      {[0.25, 0.5, 0.75].map(g => <line key={g} x1={pad} x2={width-pad} y1={pad + g*h} y2={pad + g*h} stroke="#f1f5f9" strokeDasharray="2 3" />)}
      <path d={area} fill={`url(#${gid})`} />
      <path d={smooth} fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      {pts.map((p, i) => <circle key={i} cx={p[0]} cy={p[1]} r={i === pts.length - 1 ? 4 : 2.5} fill="white" stroke={color} strokeWidth="2" />)}
    </svg>
  );
};

const Popover = ({ trigger, children, align = 'left', width = 'w-56', openUp: openUpProp }) => {
  const [open, setOpen] = useState(false);
  const [autoOpenUp, setAutoOpenUp] = useState(false);
  const ref = useRef(null);
  const triggerRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    const onClick = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', onClick);
    return () => document.removeEventListener('mousedown', onClick);
  }, [open]);

  // When opening, check if there's enough space below; if not, flip upward
  useEffect(() => {
    if (!open || openUpProp !== undefined) return;
    const el = triggerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const spaceBelow = window.innerHeight - rect.bottom;
    const ESTIMATED_HEIGHT = 280; // generous default for a typical menu
    setAutoOpenUp(spaceBelow < ESTIMATED_HEIGHT && rect.top > spaceBelow);
  }, [open, openUpProp]);

  const opensUp = openUpProp ?? autoOpenUp;

  return (
    <div className="relative inline-block" ref={ref}>
      <div ref={triggerRef} onClick={() => setOpen(v => !v)}>{trigger(open)}</div>
      {open && (
        <div className={`absolute z-50 ${opensUp ? 'bottom-full mb-1.5' : 'top-full mt-1.5'} ${align === 'right' ? 'right-0' : 'left-0'} ${width} bg-white rounded-xl ring-1 ring-slate-200 shadow-xl p-1`}>
          {typeof children === 'function' ? children(() => setOpen(false)) : children}
        </div>
      )}
    </div>
  );
};

