// ---------- Top Bar ----------
const TopBar = ({ screenLabel, role, setRole, onOpenMessenger, onOpenPalette, onOpenNotif, onOpenSidebar, onNewTask, unreadMsgs, unreadNotif, onGoToWorkspace, onUniversalNav }) => {
  const [now, setNow] = useState(new Date());
  const { tzPrimary, tzAdditional, tasks, ideas, permissions } = useApp();
  const apiBase = import.meta.env.VITE_API_BASE_URL || 'http://localhost:8787';
  // Track save freshness for the indicator. Recomputed when state actually changes,
  // and ticked once a minute so the "Xm ago" label stays current even when idle.
  const [savedAt, setSavedAt] = useState(() => storage.lastSavedAt());
  const [savePulse, setSavePulse] = useState(false);
  const [cloudStatus, setCloudStatus] = useState('idle');
  const [dbCounts, setDbCounts] = useState(() => ORBIT_LAST_DB_COUNTS);
  useEffect(() => {
    // Tick once per minute — close enough for a header clock, doesn't churn renders
    const id = setInterval(() => { setNow(new Date()); setSavedAt(storage.lastSavedAt()); }, 60_000);
    return () => clearInterval(id);
  }, []);
  useEffect(() => {
    const onSaved = (event) => {
      setSavedAt(normalizeSavedAt(event.detail?.savedAt) || storage.lastSavedAt());
      setSavePulse(true);
      window.setTimeout(() => setSavePulse(false), 900);
    };
    window.addEventListener('orbit:auto-save', onSaved);
    return () => window.removeEventListener('orbit:auto-save', onSaved);
  }, []);
  useEffect(() => {
    let alive = true;
    const loadCounts = async () => {
      try {
        const response = await fetch(`${apiBase}/db/counts`);
        const payload = await response.json();
        if (alive && payload?.ok) { ORBIT_LAST_DB_COUNTS = payload; setDbCounts(payload); }
      } catch (_) {
        if (alive && !ORBIT_LAST_DB_COUNTS.connected) setDbCounts(ORBIT_DB_COUNTS_FALLBACK);
      }
    };
    loadCounts();
    const id = setInterval(loadCounts, 15_000);
    window.addEventListener('orbit:db-counts-refresh', loadCounts);
    return () => { alive = false; clearInterval(id); window.removeEventListener('orbit:db-counts-refresh', loadCounts); };
  }, [apiBase]);
  // Refresh savedAt 400ms after any meaningful state change (just after the auto-save debounce)
  useEffect(() => {
    const t = setTimeout(() => setSavedAt(storage.lastSavedAt()), 400);
    return () => clearTimeout(t);
  }, [tasks, ideas, permissions, tzPrimary, tzAdditional, role]);
  const primary = getTZInfo(tzPrimary);
  const primaryTime = formatInTZ(now, tzPrimary, { hour: 'numeric', minute: '2-digit', hour12: true });
  // "Saved Xs ago" label
  const savedAgo = (() => {
    if (!savedAt) return null;
    const d = new Date(normalizeSavedAt(savedAt) || savedAt);
    if (isNaN(d.getTime())) return null;
    const secs = Math.floor((Date.now() - d.getTime()) / 1000);
    if (secs < 5) return 'just now';
    if (secs < 60) return `${secs}s ago`;
    const mins = Math.floor(secs / 60);
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return formatIST(d, { day: 'numeric', month: 'short' });
  })();
  return (
    <header className="sticky top-0 z-20 h-16 bg-white/90 backdrop-blur border-b border-slate-200/80 flex items-center justify-between px-3 sm:px-6 gap-2">
      <div className="hidden sm:flex items-center gap-2 text-sm shrink-0">
        <button onClick={() => onUniversalNav?.('dashboard')} className="text-slate-500 hover:text-slate-900 font-semibold inline-flex items-center gap-1.5">
          <CheckSquare className="h-3.5 w-3.5 text-indigo-500" />
          Plans &amp; Tasks
        </button>
        <ChevronRight className="h-3.5 w-3.5 text-slate-300" />
        <span className="text-slate-900 font-semibold truncate max-w-[200px]">{screenLabel}</span>
      </div>
      <div className="flex sm:hidden items-center text-sm shrink-0">
        <span className="text-slate-900 font-semibold truncate max-w-[160px]">{screenLabel}</span>
      </div>
      <UniversalAppSearch onNavigate={onUniversalNav} fallbackSearch={onOpenPalette} />
      <button onClick={onOpenPalette} className="md:hidden h-9 w-9 grid place-items-center rounded-lg bg-slate-50 border border-slate-200 text-slate-600 hover:bg-white shrink-0">
        <Search className="h-4 w-4" />
      </button>
      <div className="flex items-center gap-1.5 sm:gap-2 shrink-0">
        {/* Primary workspace clock */}
        <div title={`Workspace timezone: ${primary.city} (${primary.code || ''} · ${primary.country || tzPrimary})`} className="hidden md:flex items-center gap-1.5 h-9 px-2.5 rounded-lg bg-slate-50 border border-slate-200">
          <Clock className="h-3.5 w-3.5 text-slate-400" />
          <span className="text-[13px] text-slate-700 font-semibold tabular-nums">{primaryTime}</span>
          <span className="text-[11px] text-slate-400 font-semibold tracking-wider">{primary.code || 'TZ'}</span>
        </div>
        {/* Additional world clocks — up to 3 */}
        {tzAdditional.length > 0 && (
          <div className="hidden xl:flex items-center gap-1">
            {tzAdditional.slice(0, 3).map(tz => {
              const info = getTZInfo(tz);
              const time = formatInTZ(now, tz, { hour: 'numeric', minute: '2-digit', hour12: true });
              return (
                <div key={tz} title={`${info.city} (${info.code} · ${info.country})`} className="flex items-center gap-1.5 h-9 px-2 rounded-lg bg-white border border-slate-200">
                  <span className="text-[13px]">{info.flag}</span>
                  <span className="text-[13px] text-slate-700 font-medium tabular-nums">{time}</span>
                  <span className="text-[11px] text-slate-400 font-semibold tracking-wider">{info.code}</span>
                </div>
              );
            })}
          </div>
        )}
        <div title={dbCounts.connected ? `Database connected. ${dbCounts.totalTables || 0} tables, ${dbCounts.activeTables || 0} with rows, ${dbCounts.totalRows || 0} rows.` : 'Database not connected yet. Currently saving locally in this browser.'} className={`hidden xl:inline-flex h-9 px-2 items-center gap-1.5 rounded-lg border ${dbCounts.connected ? 'bg-sky-50 border-sky-200' : 'bg-slate-50 border-slate-200'}`}>
          <Database className={`h-4 w-4 ${dbCounts.connected ? 'text-sky-600' : 'text-slate-400'}`} />
          <span className="text-[11px] font-bold tabular-nums text-slate-700">{dbCounts.totalTables || 0}</span>
          <Layers className={`h-4 w-4 ${dbCounts.connected ? 'text-sky-600' : 'text-slate-400'}`} />
          <span className="text-[11px] font-bold tabular-nums text-slate-700">{dbCounts.totalRows || 0}</span>
        </div>
        {/* Auto-save indicator — shows persistence is on and when last write happened */}
        <div title={savedAt ? `Last auto-saved: ${formatIST(new Date(savedAt), { hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true })}${savedAgo ? ` (${savedAgo})` : ''}` : 'Not saved yet'} className={`hidden md:grid h-9 w-9 place-items-center rounded-lg border transition-colors duration-300 ${savePulse ? 'bg-indigo-600 border-indigo-600' : 'bg-emerald-50 border-emerald-200'}`}>
          <Save className={`h-4 w-4 transition-colors ${savePulse ? 'text-white' : 'text-emerald-600'}`} />
        </div>
        <button onClick={onOpenNotif} className="relative h-9 w-9 grid place-items-center rounded-lg bg-slate-50 border border-slate-200 text-slate-600 hover:bg-white hover:text-slate-900">
          <Bell className="h-4 w-4" />
          {unreadNotif > 0 && <span className="absolute -top-1 -right-1 h-4 min-w-[16px] px-1 rounded-full bg-rose-500 text-white text-[11px] font-bold grid place-items-center ring-2 ring-white">{unreadNotif}</span>}
        </button>
        <button onClick={onOpenMessenger} className="relative h-9 w-9 grid place-items-center rounded-lg bg-slate-50 border border-slate-200 text-slate-600 hover:bg-white hover:text-slate-900">
          <MessageCircle className="h-4 w-4" />
          {unreadMsgs > 0 && <span className="absolute -top-1 -right-1 h-4 min-w-[16px] px-1 rounded-full bg-rose-500 text-white text-[11px] font-bold grid place-items-center ring-2 ring-white">{unreadMsgs}</span>}
        </button>
        <button onClick={onNewTask} title="Create new task" className="h-9 px-2.5 sm:px-3 inline-flex items-center gap-1.5 rounded-lg bg-slate-900 text-white text-[13px] font-medium hover:bg-slate-800 shadow-sm">
          <Plus className="h-4 w-4" /><span className="hidden sm:inline">Task</span>
        </button>
        <PlatformContextSwitcher compact />
        <UserPerspectiveSwitcher compact />
      </div>
    </header>
  );
};

