const CommSetup_Screen = () => {
  const [tab, setTab] = useState('channels'); // 'channels' | 'templates' | 'logs'

  const TABS = [
    { id: 'channels',  label: 'Channels',          icon: MessageCircle, desc: 'WhatsApp + Email connection' },
    { id: 'templates', label: 'Message Templates', icon: MessageSquare, desc: 'Content sent for each event' },
    { id: 'logs',      label: 'Activity Logs',     icon: BellDot,       desc: 'Delivery history & status' },
  ];

  return (
    <ScreenFrame title="Communication Setup" subtitle="How Orbit reaches your team — channels, templates, and delivery logs" icon={MessageCircle}>
      {/* Tab navigation */}
      <Card className="p-2 flex items-center gap-1 overflow-x-auto">
        {TABS.map(t => {
          const Icon = t.icon;
          const active = tab === t.id;
          return (
            <button key={t.id} onClick={() => setTab(t.id)} className={`flex items-center gap-2 px-3 py-2 rounded-lg transition shrink-0 ${active ? 'bg-indigo-50 ring-1 ring-indigo-200' : 'hover:bg-slate-50'}`}>
              <div className={`h-7 w-7 rounded-md grid place-items-center ${active ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                <Icon className="h-3.5 w-3.5" />
              </div>
              <div className="text-left">
                <div className={`text-[13px] font-semibold ${active ? 'text-indigo-900' : 'text-slate-900'}`}>{t.label}</div>
                <div className="text-[11px] text-slate-500 leading-tight">{t.desc}</div>
              </div>
            </button>
          );
        })}
      </Card>

      {/* Tab content — nested screens render their own ScreenFrame */}
      {tab === 'channels'  && <CommSetup_ChannelsTab />}
      {tab === 'templates' && <MessageTemplates_Screen embedded />}
      {tab === 'logs'      && <CommSetup_LogsTab />}
    </ScreenFrame>
  );
};

