// ===== Unassigned system user — holding zone for orphaned tasks =====
// Used when a member is archived but their tasks need a temporary owner.
// Auto-created on first load. Cannot be edited, archived, or deleted.
const UNASSIGNED_USER_ID = 'u-unassigned';
const UNASSIGNED_USER_TEMPLATE = {
  id: UNASSIGNED_USER_ID,
  name: 'Unassigned',
  email: '',
  role: 'member',
  dept: null,
  empId: '—',
  status: 'active',
  isSystem: true,                  // flag for everywhere that needs to know
  hoursPerWeek: 0,
  daysPerWeek: 5,
  dailyCapacityMinutes: 0,
  engagement: 'system',
  joinedAt: '',
  noticeAt: '',
  exitAt: '',
  ktDismissed: false,
  kras: [], kpis: [], reviews: [], documents: [],
  resignationNote: '',
  offerLetterUrl: '', completionLetterUrl: '',
  appAccess: [],
};
const isSystemUser = (u) => u && (u.isSystem === true || u.id === UNASSIGNED_USER_ID);
const isSuspendedUser = (u) => (u?.status || 'active') === 'suspended';
const isActiveUser = (u) => (u?.status || 'active') === 'active' && !u?.archived && !isSystemUser(u);
const ROLE_ALIASES = { owner: 'studio_owner', user: 'member' };
const normalizeWorkspaceRole = (role) => ROLE_ALIASES[String(role || 'member').toLowerCase()] || String(role || 'member').toLowerCase();
const PLATFORM_ROLE_IDS = ['super_admin', 'product_admin'];
const ORG_ADMIN_ROLE_IDS = ['super_admin', 'product_admin', 'studio_owner', 'admin'];
const MANAGERIAL_ROLE_IDS = [...ORG_ADMIN_ROLE_IDS, 'manager'];
const isWorkspaceAdminRole = (role) => ORG_ADMIN_ROLE_IDS.includes(normalizeWorkspaceRole(role));
const isManagerialRole = (role) => MANAGERIAL_ROLE_IDS.includes(normalizeWorkspaceRole(role));

