const orbitRuntimeRoleForPlatformRole = (role) => {
  const normalized = normalizeWorkspaceRole(role);
  if (ORG_ADMIN_ROLE_IDS.includes(normalized)) return 'admin';
  if (normalized === 'manager') return 'manager';
  return 'user';
};

const firstValue = (...values) => values.find(value => value !== undefined && value !== null && String(value).trim() !== '');

const PLATFORM_APP_ID_ALIASES = {
  plans: 'orbit',
  tasks: 'orbit',
  people: 'hr',
  users: 'hr',
  documents: 'docExpress',
  docs: 'docExpress',
  doc_express: 'docExpress',
};

const normalizePlatformAppAccess = (values = []) => Array.from(new Set(
  (Array.isArray(values) ? values : [])
    .map(value => String(value || '').trim())
    .filter(Boolean)
    .map(value => PLATFORM_APP_ID_ALIASES[value] || value)
));

const normalizePlatformMembershipRow = (row = {}) => ({
  id: String(firstValue(row.id, row.membership_id, `membership-${row.email || row.user_email || Date.now()}`)),
  organizationId: String(firstValue(row.organization_id, row.organizationId, row.org_id, '')),
  workspaceId: String(firstValue(row.workspace_id, row.workspaceId, row.ws_id, '')),
  userId: String(firstValue(row.user_id, row.userId, '')),
  email: String(firstValue(row.email, row.user_email, row.member_email, row.invited_email, '')).trim().toLowerCase(),
  name: String(firstValue(row.name, row.full_name, row.member_name, row.display_name, row.email, row.user_email, 'Member')),
  role: normalizeWorkspaceRole(firstValue(row.role, row.platform_role, row.workspace_role, 'member')),
  status: String(firstValue(row.status, 'active')).toLowerCase(),
  appAccess: normalizePlatformAppAccess(Array.isArray(row.app_access) ? row.app_access : Array.isArray(row.appAccess) ? row.appAccess : []),
  raw: row,
});

const platformContextToTenants = (payload = {}) => {
  const orgRows = Array.isArray(payload.organizations) ? payload.organizations : [];
  const workspaceRows = Array.isArray(payload.workspaces) ? payload.workspaces : [];
  if (!orgRows.length) return [];

  return orgRows.map((org) => {
    const orgId = String(firstValue(org.id, org.organization_id, org.org_id, ''));
    const workspaces = workspaceRows
      .filter(ws => String(firstValue(ws.organization_id, ws.organizationId, ws.org_id, '')) === orgId)
      .map(ws => ({
        id: String(firstValue(ws.id, ws.workspace_id, ws.ws_id, '')),
        name: String(firstValue(ws.name, ws.workspace_name, ws.title, 'Workspace')),
        slug: String(firstValue(ws.slug, ws.workspace_slug, 'workspace')),
        status: String(firstValue(ws.status, 'active')),
        kind: String(firstValue(ws.kind, ws.type, 'workspace')),
      }))
      .filter(ws => ws.id);

    return {
      id: orgId,
      name: String(firstValue(org.name, org.organization_name, org.title, org.slug, 'Organization')),
      slug: String(firstValue(org.slug, org.organization_slug, 'organization')),
      status: String(firstValue(org.status, 'active')),
      plan: String(firstValue(org.plan, org.plan_name, 'trial')),
      ownerName: String(firstValue(org.owner_name, org.ownerName, org.contact_name, '')),
      ownerEmail: String(firstValue(org.owner_email, org.ownerEmail, org.email, '')),
      region: String(firstValue(org.region, org.country, '')),
      workspaces: workspaces.length ? workspaces : [{ id: `${orgId}-workspace`, name: 'Main Workspace', slug: 'main', status: 'active', kind: 'workspace' }],
    };
  }).filter(org => org.id);
};

const realWorkspaceUsers = (users = []) =>
  users.filter(u => !isSystemUser(u) && !u.archived);

const orbitRoleForUser = (u) => {
  const role = normalizeWorkspaceRole(u?.role);
  if (isWorkspaceAdminRole(role)) return 'admin';
  if (role === 'manager') return 'manager';
  return 'user';
};

const taskStatusBucket = (status) => {
  if (['completed', 'approved'].includes(status)) return 'completed';
  if (['in_progress', 'submitted', 'pending', 'revision', 'overdue'].includes(status)) return 'inProgress';
  if (['draft', 'scheduled', 'assigned'].includes(status)) return 'notStarted';
  return 'notStarted';
};

const taskAnalysisForUser = (tasks = [], userId) => {
  const assigned = tasks.filter(t => t.assignedTo === userId);
  const counts = assigned.reduce((acc, t) => {
    acc[taskStatusBucket(t.status)] += 1;
    return acc;
  }, { total: assigned.length, notStarted: 0, inProgress: 0, completed: 0 });
  counts.open = counts.notStarted + counts.inProgress;
  counts.percent = counts.total ? Math.round((counts.completed / counts.total) * 10000) / 100 : 0;
  return counts;
};

const userTaskAnalysisRows = (users = [], tasks = []) =>
  realWorkspaceUsers(users).map(u => ({ user: u, ...taskAnalysisForUser(tasks, u.id) }));

const UserPerspectiveSwitcher = ({ compact = false }) => {
  const { users, tasks, role, setRole, viewUserId, setViewUserId, toast } = useApp();
  const [open, setOpen] = useState(false);
  const people = realWorkspaceUsers(users).filter(u => (u.status || 'active') === 'active');
  const selected = people.find(u => u.id === viewUserId) || people[0] || users.find(u => u.id === viewUserId);
  const analysis = taskAnalysisForUser(tasks, selected?.id);
  const switchablePeople = people.filter(u => u.id !== selected?.id);

  const switchTo = (u) => {
    if (!u) return;
    setViewUserId(u.id);
    setRole(orbitRoleForUser(u));
    setOpen(false);
    toast?.(`Viewing as ${u.name}`);
  };

  if (!selected) return null;

  return (
    <div className="relative hidden sm:block">
      <button onClick={() => setOpen(v => !v)} title="View the app as a mapped user" className={`h-9 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 inline-flex items-center gap-2 ${compact ? 'px-2' : 'px-2.5'}`}>
        <Avatar id={selected.id} size="xs" />
        {!compact && (
          <div className="text-left leading-tight">
            <div className="text-[12px] font-semibold text-slate-800 max-w-[130px] truncate">{selected.name}</div>
            <div className="text-[10px] text-slate-400 capitalize">{role} view</div>
          </div>
        )}
        <ChevronDown className="h-3.5 w-3.5 text-slate-400" />
      </button>
      {open && (<>
        <div className="fixed inset-0 z-30" onClick={() => setOpen(false)} />
        <div className="absolute right-0 mt-1.5 w-80 max-h-[70vh] overflow-hidden bg-white rounded-xl ring-1 ring-slate-200 shadow-xl z-40">
          <div className="p-3 border-b border-slate-100">
            <div className="text-[11px] font-semibold text-slate-400 uppercase tracking-wider">Viewing As</div>
            <div className="mt-2 flex items-center gap-2">
              <Avatar id={selected.id} />
              <div className="min-w-0 flex-1">
                <div className="text-[13px] font-bold text-slate-900 truncate">{selected.name}</div>
                <div className="text-[11px] text-slate-500 truncate">{dept(selected.dept)?.name || 'No department'} · {selected.empId || selected.role}</div>
              </div>
              <div className="text-right">
                <div className="text-[13px] font-bold text-slate-900 tabular-nums">{analysis.open}</div>
                <div className="text-[10px] text-slate-400">open</div>
              </div>
            </div>
          </div>
          <div className="max-h-[46vh] overflow-y-auto p-1">
            {switchablePeople.map(u => {
              const row = taskAnalysisForUser(tasks, u.id);
              return (
                <button key={u.id} onClick={() => switchTo(u)} className="w-full flex items-center gap-2.5 px-3 py-2 rounded-lg text-left hover:bg-slate-50">
                  <Avatar id={u.id} size="sm" />
                  <div className="flex-1 min-w-0">
                    <div className="text-[13px] font-semibold truncate text-slate-900">{u.name}</div>
                    <div className="text-[11px] text-slate-500 truncate">{dept(u.dept)?.name || 'No department'} · {u.empId || u.role}</div>
                    <div className="text-[11px] text-slate-500 truncate">{row.total} tasks · {row.inProgress} in progress · {row.completed} done</div>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </>)}
    </div>
  );
};

const UserWiseAnalysisPanel = ({ users, tasks, selectedUserId, onSelectUser }) => {
  const rows = userTaskAnalysisRows(users, tasks);
  const totals = rows.reduce((acc, r) => ({
    total: acc.total + r.total,
    notStarted: acc.notStarted + r.notStarted,
    inProgress: acc.inProgress + r.inProgress,
    completed: acc.completed + r.completed,
  }), { total: 0, notStarted: 0, inProgress: 0, completed: 0 });
  const totalPct = totals.total ? Math.round((totals.completed / totals.total) * 10000) / 100 : 0;

  return (
    <div className="mx-2 mb-3 rounded-xl bg-white ring-1 ring-slate-200 overflow-hidden">
      <div className="px-3 py-2 border-b border-slate-100 bg-slate-50/80">
        <div className="flex items-center gap-1.5">
          <BarChart3 className="h-3.5 w-3.5 text-slate-500" />
          <span className="text-[11px] font-bold text-slate-700 uppercase tracking-wider">User Analysis</span>
        </div>
      </div>
      <div className="grid grid-cols-5 gap-1 px-2 py-1.5 text-[10px] font-semibold text-slate-400 uppercase tracking-wider">
        <div>User</div><div className="text-right">Total</div><div className="text-right">Open</div><div className="text-right">Prog</div><div className="text-right">Done</div>
      </div>
      <div className="max-h-[280px] overflow-y-auto px-1 pb-1">
        {rows.map(r => (
          <button key={r.user.id} onClick={() => onSelectUser?.(r.user.id)} className={`w-full grid grid-cols-5 gap-1 items-center px-2 py-1.5 rounded-lg text-[11px] hover:bg-slate-50 ${selectedUserId === r.user.id ? 'bg-indigo-50 text-indigo-800' : 'text-slate-700'}`}>
            <div className="flex items-center gap-1.5 min-w-0">
              <Avatar id={r.user.id} size="xs" />
              <span className="truncate font-semibold">{r.user.initials || r.user.name?.split(/\s+/).map(w => w[0]).join('').slice(0,2)}</span>
            </div>
            <div className="text-right tabular-nums">{r.total}</div>
            <div className="text-right tabular-nums">{r.notStarted}</div>
            <div className="text-right tabular-nums">{r.inProgress}</div>
            <div className="text-right tabular-nums">{r.completed}</div>
          </button>
        ))}
      </div>
      <div className="grid grid-cols-5 gap-1 px-3 py-2 bg-slate-900 text-white text-[11px] font-semibold">
        <div>All</div>
        <div className="text-right tabular-nums">{totals.total}</div>
        <div className="text-right tabular-nums">{totals.notStarted}</div>
        <div className="text-right tabular-nums">{totals.inProgress}</div>
        <div className="text-right tabular-nums">{totals.completed}</div>
        <div className="col-span-5 text-right text-[10px] text-white/60">{totalPct.toFixed(2)}% completed</div>
      </div>
    </div>
  );
};

