// Role → which workspace apps that role can launch (used as fallback if user has no explicit appAccess[]).
const WORKSPACE_ROLE_ACCESS = {
  super_admin: ['admin','intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],
  product_admin: ['admin','intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],
  studio_owner: ['admin','intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],
  owner:   ['admin','intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],
  admin:   ['admin','intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],  // alias of owner
  manager: ['intranet','hr','orbit','projects','crm','brand','marketing','docExpress'],
  user:    ['intranet','orbit'],
  member:  ['intranet','orbit'],
  vendor:  ['orbit'],
  client:  ['orbit'],
};

const allowedWorkspaceAppsFor = (u, role, membership = null) => {
  if (!u || u.archived || ['inactive', 'suspended'].includes(u.status || 'active')) return [];
  if (membership && ['inactive', 'suspended', 'revoked'].includes(membership.status || 'active')) return [];
  const normalizedRole = normalizeWorkspaceRole(membership?.role || role || u.role);
  const membershipAccess = normalizePlatformAppAccess(membership?.appAccess);
  const userAccess = normalizePlatformAppAccess(u?.appAccess);
  const allowedIds = membershipAccess.length ? membershipAccess : userAccess.length ? userAccess : (WORKSPACE_ROLE_ACCESS[normalizedRole] || WORKSPACE_ROLE_ACCESS.user);
  return allowedIds.map(id => WORKSPACE_APPS.find(a => a.id === id)).filter(Boolean);
};

const UniversalAppSearch = ({ onNavigate, fallbackSearch }) => {
  const { users, role, can, viewUser, activeMembership } = useApp();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const allowedApps = allowedWorkspaceAppsFor(viewUser, role, activeMembership);
  const canUseOrbit = allowedApps.some(a => a.id === 'orbit');
  const appResults = allowedApps.map(app => ({
    id: `app-${app.id}`,
    label: app.name,
    subtitle: app.subtitle,
    route: app.live && app.id === 'orbit' ? 'dashboard' : app.route,
    icon: app.icon,
    kind: 'App',
  }));
  const orbitModules = canUseOrbit
    ? [...NAV_FRONTEND, ...NAV_BACKEND]
        .filter(it => !it.perm || can(it.perm))
        .filter(it => !it.roles || it.roles.includes(role))
        .map(it => ({ id: `module-${it.id}`, label: it.label, subtitle: 'Plans & Tasks', route: it.id, icon: it.icon, kind: 'Module' }))
    : [];
  const results = [...appResults, ...orbitModules]
    .filter(item => {
      const q = query.trim().toLowerCase();
      if (!q) return true;
      return `${item.label} ${item.subtitle} ${item.kind}`.toLowerCase().includes(q);
    })
    .slice(0, 10);

  const choose = (item) => {
    setOpen(false);
    setQuery('');
    if (item?.route && onNavigate) onNavigate(item.route);
  };

  const onKeyDown = (e) => {
    if (e.key === 'Enter') {
      if (results[0]) choose(results[0]);
      else fallbackSearch?.();
    }
    if (e.key === 'Escape') {
      setOpen(false);
      setQuery('');
    }
  };

  return (
    <div className="relative flex-1 max-w-xl mx-2 sm:mx-8 hidden md:block">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none z-10" />
      <input
        value={query}
        onFocus={() => setOpen(true)}
        onChange={(e) => { setQuery(e.target.value); setOpen(true); }}
        onKeyDown={onKeyDown}
        placeholder="Search apps and modules..."
        className="w-full h-9 pl-9 pr-12 rounded-lg bg-slate-50 border border-slate-200 text-[13px] text-slate-700 placeholder:text-slate-400 hover:bg-white hover:border-slate-300 focus:bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500/20 transition"
      />
      <kbd className="absolute right-2.5 top-1/2 -translate-y-1/2 text-[11px] text-slate-400 bg-white border border-slate-200 rounded px-1.5 py-0.5">⌘K</kbd>
      {open && (
        <>
          <div className="fixed inset-0 z-30" onClick={() => { setOpen(false); setQuery(''); }} />
          <div className="absolute left-0 right-0 mt-1.5 bg-white rounded-xl ring-1 ring-slate-200 shadow-xl p-1 z-40 overflow-hidden">
            {results.length === 0 ? (
              <button onClick={fallbackSearch} className="w-full text-left px-3 py-3 text-[13px] text-slate-500 hover:bg-slate-50 rounded-lg">No app/module match. Open full command search.</button>
            ) : results.map(item => {
              const Icon = item.icon;
              return (
                <button key={item.id} onClick={() => choose(item)} className="w-full flex items-center gap-2.5 px-3 py-2 rounded-lg text-left hover:bg-slate-50">
                  <div className="h-8 w-8 rounded-lg bg-slate-100 text-slate-600 grid place-items-center shrink-0">
                    <Icon className="h-4 w-4" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="text-[13px] font-semibold text-slate-900 truncate">{item.label}</div>
                    <div className="text-[11px] text-slate-500 truncate">{item.kind} · {item.subtitle}</div>
                  </div>
                  <ArrowRight className="h-3.5 w-3.5 text-slate-300" />
                </button>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
};

