                    <div className="flex items-center gap-1 mt-4 text-[12px] font-semibold text-indigo-700 group-hover:text-indigo-900">
                      Open{app.live ? ' app' : ' preview'} <ArrowRight className="h-3.5 w-3.5 group-hover:translate-x-1 transition" />
                    </div>
