                    <select value={platformMemberForm.workspaceId} onChange={(e) => setPlatformMemberForm(prev => ({ ...prev, workspaceId: e.target.value }))} className="w-full h-10 px-3 rounded-lg bg-white border border-slate-200 text-[13px]">
                      {workspaceOptionsForOrg(platformMemberForm.organizationId).map(ws => <option key={ws.id} value={ws.id}>{ws.name}</option>)}
                    </select>
