const BrandAnalyticsDrawer = ({ project, links, events, onRefresh, onClose }) => {
  const [q, setQ] = useState('');
  const rows = links.flatMap(link => (link.recipients?.length ? link.recipients : [{ name: 'Public link visitor', email: '', phone: '', status: (link.total_views || 0) ? 'Viewed' : 'Not Viewed', lastViewed: link.last_viewed_at || '', views: link.total_views || 0, timeSpent: '0m', token: link.token }]));
  const filtered = rows.filter(r => !q || [r.name, r.email, r.phone, r.token, r.status].join(' ').toLowerCase().includes(q.toLowerCase()));
  return (
    <div className="fixed inset-0 z-[95] pointer-events-none">
      <div className="absolute inset-0 bg-slate-950/20 pointer-events-auto" onClick={onClose} />
      <aside className="absolute right-0 top-0 h-full w-full max-w-xl bg-white shadow-2xl pointer-events-auto flex flex-col">
        <div className="p-5 border-b border-slate-100 flex items-start justify-between gap-3">
          <div><div className="text-[18px] font-black text-slate-900">Portfolio Analytics</div><div className="text-[12px] text-slate-500">{brandItemTitle(project)}</div></div>
          <div className="flex items-center gap-2">
            <button onClick={onRefresh} className="h-9 px-3 rounded-lg border border-slate-200 text-[12px] font-bold text-slate-700 hover:bg-slate-50 inline-flex items-center gap-1.5"><RefreshCw className="h-3.5 w-3.5" />Refresh</button>
            <button onClick={onClose} className="h-9 w-9 rounded-lg hover:bg-slate-100 grid place-items-center"><X className="h-5 w-5" /></button>
          </div>
        </div>
        <div className="p-5 space-y-4 overflow-y-auto">
          <div className="grid grid-cols-2 gap-3"><BrandFact label="Total Views" value={links.reduce((s, l) => s + (l.total_views || 0), 0) + events.length} /><BrandFact label="Unique Visitors" value={links.reduce((s, l) => s + (l.unique_views || 0), 0)} /><BrandFact label="Links Generated" value={links.length} /><BrandFact label="Recipients" value={rows.length} /></div>
          <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" /><input value={q} onChange={e => setQ(e.target.value)} placeholder="Search recipients..." className="w-full h-10 pl-9 pr-3 rounded-xl border border-slate-200 text-[13px]" /></div>
          <div className="space-y-2">{filtered.map((r, idx) => <div key={`${r.token}-${idx}`} className="rounded-2xl border border-slate-200 p-3"><div className="flex items-center justify-between gap-3"><div><div className="text-[13px] font-bold text-slate-900">{r.name || 'Recipient'}</div><div className="text-[11px] text-slate-500">{r.email || r.phone || r.token}</div></div><span className={`px-2 py-1 rounded-full text-[10px] font-bold ${String(r.status).includes('Viewed') ? 'bg-emerald-50 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>{r.status || 'Not Viewed'}</span></div><div className="mt-2 grid grid-cols-3 gap-2 text-[11px] text-slate-500"><div>{r.lastViewed || 'Not yet'}</div><div>{r.views || 0} views</div><div>{r.timeSpent || '0m'} spent</div></div></div>)}</div>
        </div>
      </aside>
    </div>
  );
};

