      <div className="rounded-xl bg-slate-50 p-3"><div className="text-slate-400 text-[10px] font-bold uppercase">Imported At</div><div className="font-semibold text-slate-800">{exportedAt ? formatISTShortDate(exportedAt) : '-'}</div></div>
