const marketingDateLabel = (value) => {
  if (!value) return '-';
  const d = new Date(value);
  if (isNaN(d.getTime())) return value;
  return d.toLocaleString('en-IN', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
};

const MarketingToggle = ({ active, onClick }) => (
  <button onClick={onClick} className={`relative h-6 w-11 rounded-full transition ${active ? 'bg-indigo-600' : 'bg-slate-200'}`}>
    <span className={`absolute top-0.5 h-5 w-5 rounded-full bg-white shadow transition ${active ? 'left-5' : 'left-0.5'}`} />
  </button>
);

const MarketingChatbots_Tab = () => {
  const { marketingChatbots, setMarketingChatbots, toast, confirmAction } = useApp();
  const [search, setSearch] = useState('');
  const [creator, setCreator] = useState('all');
  const [simMessage, setSimMessage] = useState('Download Framework');
  const [simResult, setSimResult] = useState(null);
  const [simBusy, setSimBusy] = useState(false);
  const creators = Array.from(new Set(marketingChatbots.map(c => c.createdBy).filter(Boolean)));
  const filtered = marketingChatbots.filter(bot => {
    if (creator !== 'all' && bot.createdBy !== creator) return false;
    const q = search.trim().toLowerCase();
    if (!q) return true;
    return [bot.name, bot.triggerWord, bot.triggerType, bot.createdBy].some(v => String(v || '').toLowerCase().includes(q));
  });
  const active = marketingChatbots.filter(b => b.active).length;
  const inactive = marketingChatbots.length - active;
  const addBot = (kind = 'blank') => {
    const now = new Date().toISOString();
    const name = kind === 'template' ? 'New template chatbot' : kind === 'ai' ? 'AI draft chatbot' : 'Untitled chatbot';
    setMarketingChatbots(prev => [{ id: 'cb' + Date.now(), name, active: false, triggerWord: '', triggerType: 'MATCH KEYWORD', triggered: 0, createdBy: 'Shanker De', createdAt: now, updatedAt: now, folder: '' }, ...prev]);
    toast('Chatbot draft added');
  };
  const updateBot = (id, patch) => setMarketingChatbots(prev => prev.map(b => b.id === id ? { ...b, ...patch, updatedAt: new Date().toISOString() } : b));
  const deleteBot = async (bot) => {
    const ok = await confirmAction({ title: `Delete "${bot.name}"?`, message: 'This removes the chatbot draft from Marketing automation.', confirmLabel: 'Delete', danger: true });
    if (!ok) return;
    setMarketingChatbots(prev => prev.filter(b => b.id !== bot.id));
    toast('Chatbot deleted');
  };
  const runSimulation = async () => {
    if (!simMessage.trim()) { toast('Type a trigger message first'); return; }
    setSimBusy(true);
    try {
      const response = await fetch(`${API_BASE_URL}/marketing/chatbot/simulate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: simMessage, from: '919999999999@c.us' }),
      });
      const payload = await response.json().catch(() => ({}));
      if (!response.ok || !payload.ok) throw new Error(payload.error || 'Simulation failed');
      setSimResult(payload);
      toast(payload.matched ? `Matched ${payload.bot?.name || 'chatbot'}` : 'No chatbot matched');
    } catch (error) {
      toast(`Simulation failed: ${error.message}`);
      setSimResult({ ok: false, error: error.message });
    } finally {
      setSimBusy(false);
    }
  };

  return (
    <div className="space-y-5">
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div>
          <div className="flex items-center gap-2">
            <h1 className="text-[30px] font-black text-slate-900">Chatbots</h1>
            <span className="px-2 py-0.5 rounded-full bg-indigo-50 text-indigo-700 ring-1 ring-indigo-100 text-[11px] font-bold">Beta</span>
          </div>
          <p className="text-[14px] text-slate-500">Smart chats. Smarter business.</p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search chatbot" className="h-10 w-64 pl-9 pr-3 rounded-lg border border-slate-200 bg-white text-[13px]" />
          </div>
          <select value={creator} onChange={e => setCreator(e.target.value)} className="h-10 px-3 rounded-lg border border-slate-200 bg-white text-[13px]">
            <option value="all">Filter by creator</option>
            {creators.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button className="h-10 px-3.5 rounded-lg bg-white ring-1 ring-indigo-200 text-indigo-700 text-[13px] font-semibold inline-flex items-center gap-1.5"><PlayCircle className="h-3.5 w-3.5" />Watch Tutorial</button>
        </div>
      </div>

      <Card className="p-5">
        <div className="grid md:grid-cols-3 gap-4">
          {[
            ['Start from blank', 'Just drag and drop the elements', Copy, () => addBot('blank')],
            ['Use Pre-built Templates', 'Choose and edit', LayoutGrid, () => addBot('template')],
            ['Create with AI', 'Type your description and refine later', Sparkles, () => addBot('ai')],
          ].map(([title, desc, Icon, action]) => (
            <button key={title} onClick={action} className="min-h-[96px] rounded-xl bg-white ring-1 ring-slate-200 p-5 flex items-center gap-4 text-left hover:ring-indigo-300 hover:shadow-sm transition">
              <span className="h-12 w-12 rounded-xl bg-slate-50 text-slate-500 grid place-items-center"><Icon className="h-6 w-6" /></span>
              <span><span className="block text-[15px] font-bold text-slate-800">{title}</span><span className="block text-[12px] text-slate-400 mt-1">{desc}</span></span>
            </button>
          ))}
        </div>
      </Card>

      <div className="grid md:grid-cols-3 gap-4">
        <MarketingMetric icon={MessageCircle} label="Total Chatbots" value={marketingChatbots.length} />
        <MarketingMetric icon={CheckCircle2} label="Active Chatbots" value={active} tone="text-emerald-700" />
        <MarketingMetric icon={Archive} label="Inactive Chatbots" value={inactive} tone="text-rose-700" />
      </div>

      <Card className="p-4 bg-slate-950 text-white">
        <div className="flex items-start justify-between gap-4 flex-wrap">
          <div>
            <div className="text-[14px] font-black">Chatbot Logic Test</div>
            <div className="text-[12px] text-slate-300 mt-1">Tests trigger-word matching against active chatbots and previews the auto-reply.</div>
          </div>
          <div className="flex items-center gap-2 flex-1 min-w-[320px] max-w-2xl">
            <input value={simMessage} onChange={e => setSimMessage(e.target.value)} placeholder="Type an incoming WhatsApp message..." className="flex-1 h-10 px-3 rounded-lg bg-white/10 ring-1 ring-white/15 text-white placeholder:text-slate-400 text-[13px] focus:outline-none focus:ring-indigo-300" />
            <button onClick={runSimulation} disabled={simBusy} className="h-10 px-4 rounded-lg bg-indigo-500 text-white text-[13px] font-bold disabled:opacity-50 inline-flex items-center gap-1.5"><Play className="h-3.5 w-3.5" />{simBusy ? 'Testing' : 'Run'}</button>
          </div>
        </div>
        {simResult && (
          <div className="mt-4 grid md:grid-cols-2 gap-3 text-[12px]">
            <div className="rounded-xl bg-white/8 ring-1 ring-white/10 p-3"><span className="text-slate-400">Matched:</span> <span className="font-bold">{simResult.matched ? simResult.bot?.name : 'No match'}</span></div>
            <div className="rounded-xl bg-white/8 ring-1 ring-white/10 p-3 whitespace-pre-wrap"><span className="text-slate-400">Reply:</span> {simResult.reply || simResult.error || 'No reply'}</div>
          </div>
        )}
      </Card>

      <div className="grid lg:grid-cols-[240px_1fr] gap-4">
        <Card className="p-4">
          <div className="flex items-center justify-between text-[13px] font-bold text-slate-900"><span>Folders</span><button onClick={() => toast('Folders can be added once campaign categories are final.')} className="text-[11px] font-semibold text-slate-400 hover:text-indigo-600">+ New Folder</button></div>
          <div className="h-28 grid place-items-center text-[12px] text-slate-400">No folders yet</div>
        </Card>
        <Card className="overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-[13px]" style={{ minWidth: 960 }}>
              <thead className="bg-slate-50 text-[11px] uppercase tracking-wider text-slate-500">
                <tr>
                  <th className="px-4 py-3"><input type="checkbox" className="rounded border-slate-300" /></th>
                  <th className="px-4 py-3 font-bold">Name</th>
                  <th className="px-4 py-3 font-bold">Status</th>
                  <th className="px-4 py-3 font-bold">Trigger Word</th>
                  <th className="px-4 py-3 font-bold">Trigger Type</th>
                  <th className="px-4 py-3 font-bold">Triggered</th>
                  <th className="px-4 py-3 font-bold">Created By</th>
                  <th className="px-4 py-3 font-bold">Updated</th>
                  <th className="px-4 py-3 font-bold text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filtered.map(bot => (
                  <tr key={bot.id} className="hover:bg-slate-50">
                    <td className="px-4 py-3"><input type="checkbox" className="rounded border-slate-300" /></td>
                    <td className="px-4 py-3"><input value={bot.name} onChange={e => updateBot(bot.id, { name: e.target.value })} className="w-full bg-transparent font-semibold text-slate-700 focus:outline-none focus:bg-white focus:ring-1 focus:ring-indigo-200 rounded px-1" /></td>
                    <td className="px-4 py-3"><MarketingToggle active={bot.active} onClick={() => updateBot(bot.id, { active: !bot.active })} /></td>
                    <td className="px-4 py-3"><input value={bot.triggerWord || ''} onChange={e => updateBot(bot.id, { triggerWord: e.target.value })} placeholder="-" className="w-full bg-transparent text-slate-700 focus:outline-none focus:bg-white focus:ring-1 focus:ring-indigo-200 rounded px-1" /></td>
                    <td className="px-4 py-3 text-slate-600">{bot.triggerType || '-'}</td>
                    <td className="px-4 py-3 text-indigo-600 font-bold tabular-nums">{bot.triggered || 0}</td>
                    <td className="px-4 py-3 text-slate-700"><div className="font-semibold">{bot.createdBy}</div><div className="text-[10px] text-slate-400">{marketingDateLabel(bot.createdAt)}</div></td>
                    <td className="px-4 py-3 text-slate-500">{marketingDateLabel(bot.updatedAt)}</td>
                    <td className="px-4 py-3">
                      <div className="flex justify-end gap-1 text-indigo-400">
                        <button onClick={() => toast('Share link copied')} className="h-8 w-8 grid place-items-center rounded-lg hover:bg-indigo-50"><ExternalLink className="h-3.5 w-3.5" /></button>
                        <button onClick={() => addBot('copy')} className="h-8 w-8 grid place-items-center rounded-lg hover:bg-indigo-50"><Copy className="h-3.5 w-3.5" /></button>
                        <button onClick={() => toast('Chatbot editor coming after trial templates.')} className="h-8 w-8 grid place-items-center rounded-lg hover:bg-indigo-50"><Pencil className="h-3.5 w-3.5" /></button>
                        <button onClick={() => toast('Folders are ready as a storage field.')} className="h-8 w-8 grid place-items-center rounded-lg hover:bg-indigo-50"><FolderOpen className="h-3.5 w-3.5" /></button>
                        <button onClick={() => deleteBot(bot)} className="h-8 w-8 grid place-items-center rounded-lg text-rose-400 hover:bg-rose-50"><Trash2 className="h-3.5 w-3.5" /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="py-3 text-center text-[12px] text-slate-400">Showing {filtered.length} of {marketingChatbots.length} chatbots</div>
        </Card>
      </div>
    </div>
  );
};

const MarketingSequences_Tab = () => {
  const { marketingSequences, setMarketingSequences, waTemplates, toast, confirmAction } = useApp();
  const [search, setSearch] = useState('');
  const [editingId, setEditingId] = useState(null);
  const sequence = marketingSequences.find(s => s.id === editingId);
  const filtered = marketingSequences.filter(s => !search.trim() || s.name.toLowerCase().includes(search.trim().toLowerCase()));
  const active = marketingSequences.filter(s => s.active).length;
  const updateSequence = (id, patch) => setMarketingSequences(prev => prev.map(s => s.id === id ? { ...s, ...patch } : s));
  const addSequence = () => {
    const first = waTemplates[0];
    const seq = { id: 'seq' + Date.now(), name: 'new sequence', active: false, triggered: 0, createdBy: 'Shanker De', messages: first ? [{ id: 'seqm' + Date.now(), templateId: first.id, templateName: first.name, active: true, delayValue: 1, delayUnit: 'Days', scheduledFor: 'Anytime · Everyday' }] : [], logs: [] };
    setMarketingSequences(prev => [seq, ...prev]);
    setEditingId(seq.id);
    toast('Sequence added');
  };
  const deleteSequence = async (seq) => {
    const ok = await confirmAction({ title: `Delete "${seq.name}"?`, message: 'This removes the WhatsApp follow-up sequence.', confirmLabel: 'Delete', danger: true });
    if (!ok) return;
    setMarketingSequences(prev => prev.filter(s => s.id !== seq.id));
    toast('Sequence deleted');
  };

  if (sequence) {
    return <MarketingSequenceEditor sequence={sequence} templates={waTemplates} onBack={() => setEditingId(null)} onUpdate={(patch) => updateSequence(sequence.id, patch)} />;
  }

  return (
    <div className="space-y-5">
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div>
          <h1 className="text-[30px] font-black text-slate-900 inline-flex items-center gap-2">Sequence <HelpCircle className="h-4 w-4 text-slate-400" /></h1>
          <p className="text-[14px] text-slate-500">Automate your WhatsApp follow-ups with smart message sequences.</p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" /><input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search sequence" className="h-10 w-64 pl-9 pr-3 rounded-lg border border-slate-200 bg-white text-[13px]" /></div>
          <button className="h-10 px-3.5 rounded-lg bg-white ring-1 ring-indigo-200 text-indigo-700 text-[13px] font-semibold inline-flex items-center gap-1.5"><PlayCircle className="h-3.5 w-3.5" />Watch Tutorial</button>
          <button onClick={addSequence} className="h-10 px-4 rounded-lg bg-indigo-600 text-white text-[13px] font-semibold inline-flex items-center gap-1.5"><Plus className="h-3.5 w-3.5" />Add Sequence</button>
        </div>
      </div>
      <div className="grid md:grid-cols-3 gap-4">
        <MarketingMetric icon={List} label="Total Sequences" value={marketingSequences.length} />
        <MarketingMetric icon={CheckCircle2} label="Active Sequences" value={active} tone="text-emerald-700" />
        <MarketingMetric icon={Archive} label="Inactive Sequences" value={marketingSequences.length - active} tone="text-rose-700" />
      </div>
      <Card className="overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-[13px]" style={{ minWidth: 820 }}>
            <thead className="bg-slate-50 text-[11px] uppercase tracking-wider text-slate-500">
              <tr><th className="px-4 py-3 font-bold">Status</th><th className="px-4 py-3 font-bold">Sequence Name</th><th className="px-4 py-3 font-bold">Messages Count</th><th className="px-4 py-3 font-bold">Triggered</th><th className="px-4 py-3 font-bold">Created By</th><th className="px-4 py-3 font-bold text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map(seq => (
                <tr key={seq.id} className="hover:bg-slate-50">
                  <td className="px-4 py-3"><MarketingToggle active={seq.active} onClick={() => updateSequence(seq.id, { active: !seq.active })} /></td>
                  <td className="px-4 py-3"><button onClick={() => setEditingId(seq.id)} className="text-indigo-600 underline font-semibold">{seq.name}</button></td>
                  <td className="px-4 py-3 tabular-nums">{(seq.messages || []).length}</td>
                  <td className="px-4 py-3 tabular-nums">{seq.triggered || 0}</td>
                  <td className="px-4 py-3">{seq.createdBy || 'Shanker De'}</td>
                  <td className="px-4 py-3"><div className="flex justify-end gap-1"><button onClick={() => setEditingId(seq.id)} className="h-8 w-8 grid place-items-center rounded-lg text-indigo-400 hover:bg-indigo-50"><Pencil className="h-3.5 w-3.5" /></button><button onClick={() => toast('Sequence analytics will use provider events after integration.')} className="h-8 w-8 grid place-items-center rounded-lg text-indigo-400 hover:bg-indigo-50"><BarChart3 className="h-3.5 w-3.5" /></button><button onClick={() => deleteSequence(seq)} className="h-8 w-8 grid place-items-center rounded-lg text-rose-400 hover:bg-rose-50"><Trash2 className="h-3.5 w-3.5" /></button></div></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="py-4 text-center text-[12px] text-slate-400">Showing {filtered.length} of {marketingSequences.length} sequences</div>
      </Card>
    </div>
  );
};

const MarketingSequenceEditor = ({ sequence, templates, onBack, onUpdate }) => {
  const { toast } = useApp();
  const updateMessage = (id, patch) => onUpdate({ messages: (sequence.messages || []).map(m => m.id === id ? { ...m, ...patch } : m) });
  const addMessage = () => {
    const first = templates[0];
    onUpdate({ messages: [...(sequence.messages || []), { id: 'seqm' + Date.now(), templateId: first?.id || '', templateName: first?.name || 'Select template', active: true, delayValue: 1, delayUnit: 'Days', scheduledFor: 'Anytime · Everyday' }] });
    toast('Sequence message added');
  };
  const deleteMessage = (id) => onUpdate({ messages: (sequence.messages || []).filter(m => m.id !== id) });
  const steps = ['Sequence Setup', 'Exit Conditions', 'Add Messages', 'Sequence Logs'];
  return (
    <Card className="min-h-[calc(100vh-120px)] flex flex-col overflow-hidden">
      <div className="p-5 border-b border-slate-100">
        <div className="flex items-center gap-3"><button onClick={onBack} className="h-9 w-9 rounded-lg hover:bg-slate-100 grid place-items-center"><ArrowRight className="h-4 w-4 rotate-180" /></button><div><h1 className="text-[20px] font-black text-slate-900">Edit Sequence</h1><div className="text-[13px] text-slate-500">({sequence.name})</div></div></div>
        <div className="grid grid-cols-4 gap-6 mt-8">
          {steps.map((s, i) => <div key={s} className="text-center relative"><div className={`mx-auto h-10 w-10 rounded-full grid place-items-center text-[14px] font-black ${i < 3 ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{i + 1}</div><div className={`mt-2 text-[13px] ${i < 3 ? 'text-indigo-600' : 'text-slate-700'}`}>{s}</div>{i < steps.length - 1 && <div className={`hidden md:block absolute top-5 left-[60%] right-[-40%] h-0.5 ${i < 2 ? 'bg-indigo-500' : 'bg-slate-200'}`} />}</div>)}
        </div>
      </div>
      <div className="p-5 flex-1">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-[16px] font-black text-slate-900">Sequence Messages ({(sequence.messages || []).length})</h2>
          <button onClick={addMessage} className="h-9 px-4 rounded-lg bg-indigo-600 text-white text-[13px] font-semibold inline-flex items-center gap-1.5"><Plus className="h-4 w-4" />Add</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-[13px]" style={{ minWidth: 900 }}>
            <thead className="bg-slate-50 text-[11px] uppercase tracking-wider text-slate-500"><tr><th className="px-4 py-3">Status</th><th className="px-4 py-3">Template name</th><th className="px-4 py-3">Delay</th><th className="px-4 py-3">Scheduled For</th><th className="px-4 py-3 text-right">Actions</th></tr></thead>
            <tbody className="divide-y divide-slate-100">
              {(sequence.messages || []).map(m => (
                <tr key={m.id}>
                  <td className="px-4 py-3"><MarketingToggle active={m.active} onClick={() => updateMessage(m.id, { active: !m.active })} /></td>
                  <td className="px-4 py-3"><select value={m.templateId || ''} onChange={e => { const tpl = templates.find(t => t.id === e.target.value); updateMessage(m.id, { templateId: e.target.value, templateName: tpl?.name || m.templateName }); }} className="h-9 px-2 rounded-lg border border-slate-200 bg-white text-[13px]"><option value="">Select template</option>{templates.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}</select><Eye className="inline-block h-3.5 w-3.5 text-indigo-500 ml-2" /></td>
                  <td className="px-4 py-3"><div className="flex items-center gap-2"><span>After</span><input type="number" min="0" value={m.delayValue || 0} onChange={e => updateMessage(m.id, { delayValue: Number(e.target.value) })} className="h-9 w-16 px-2 rounded-lg border border-slate-200" /><select value={m.delayUnit || 'Days'} onChange={e => updateMessage(m.id, { delayUnit: e.target.value })} className="h-9 px-2 rounded-lg border border-slate-200 bg-white"><option>Minutes</option><option>Hours</option><option>Days</option></select></div></td>
                  <td className="px-4 py-3"><input value={m.scheduledFor || ''} onChange={e => updateMessage(m.id, { scheduledFor: e.target.value })} className="h-9 px-2 rounded-lg border border-slate-200 w-full" /></td>
                  <td className="px-4 py-3"><div className="flex justify-end gap-1"><button onClick={() => toast('Message editor is inline for now.')} className="h-8 w-8 grid place-items-center rounded-lg text-indigo-400 hover:bg-indigo-50"><Pencil className="h-3.5 w-3.5" /></button><button onClick={() => deleteMessage(m.id)} className="h-8 w-8 grid place-items-center rounded-lg text-rose-400 hover:bg-rose-50"><Trash2 className="h-3.5 w-3.5" /></button></div></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <div className="p-5 border-t border-slate-100 flex justify-end gap-3"><button onClick={onBack} className="h-10 px-4 rounded-lg ring-1 ring-rose-200 text-rose-600 text-[13px] font-semibold">Back</button><button onClick={() => toast('Logs will populate after the scheduler sends this sequence.')} className="h-10 px-4 rounded-lg bg-indigo-600 text-white text-[13px] font-semibold">View Logs</button></div>
    </Card>
  );
};

const MarketingDefaultActions_Tab = ({ onOpenReplyMaterial }) => {
  const { marketingDefaultActions, setMarketingDefaultActions, marketingReplyMaterials, toast } = useApp();
  const rows = marketingDefaultActions.nonWorkingHours || INITIAL_MARKETING_DEFAULT_ACTIONS.nonWorkingHours;
  const updateRow = (day, patch) => setMarketingDefaultActions(prev => ({ ...prev, nonWorkingHours: rows.map(r => r.day === day ? { ...r, ...patch } : r) }));
  const anyEnabled = rows.some(r => r.enabled);
  const selected = marketingReplyMaterials.find(m => m.id === marketingDefaultActions.selectedReplyMaterialId);
  const save = () => {
    setMarketingDefaultActions(prev => ({ ...prev, savedAt: new Date().toISOString() }));
    toast('Default actions saved');
  };
  return (
    <div className="space-y-5">
      <div className="flex items-start justify-between gap-3">
        <div><h1 className="text-[30px] font-black text-slate-900">Default Actions</h1><p className="text-[14px] text-slate-500">Handle every message with default responses outside working hours.</p><p className="text-[12px] text-slate-400 mt-1">Set non-working hours and choose the reply material sent automatically.</p></div>
        <button className="h-10 px-3.5 rounded-lg bg-white ring-1 ring-indigo-200 text-indigo-700 text-[13px] font-semibold inline-flex items-center gap-1.5"><PlayCircle className="h-3.5 w-3.5" />Watch Tutorial</button>
      </div>
      <div className="grid lg:grid-cols-[1fr_1fr] gap-5">
        <Card className="overflow-hidden">
          <div className="px-4 py-3 border-b border-slate-100 text-[14px] font-black text-slate-900">Non-working Hours</div>
          <div className="p-4 space-y-3">
            {rows.map(r => (
              <div key={r.day} className="grid grid-cols-[120px_52px_1fr_22px_1fr_40px] items-center gap-2 text-[13px]">
                <div className="font-semibold text-slate-700">{r.day}</div>
                <MarketingToggle active={r.enabled} onClick={() => updateRow(r.day, { enabled: !r.enabled })} />
                <input type="time" value={r.start} onChange={e => updateRow(r.day, { start: e.target.value })} disabled={!r.enabled} className="h-9 px-2 rounded-lg border border-slate-200 disabled:opacity-40" />
                <span className="text-slate-400 text-center">To</span>
                <input type="time" value={r.end} onChange={e => updateRow(r.day, { end: e.target.value })} disabled={!r.enabled} className="h-9 px-2 rounded-lg border border-slate-200 disabled:opacity-40" />
                <button onClick={() => updateRow(r.day, { enabled: true })} className="h-8 w-8 grid place-items-center rounded-lg bg-indigo-100 text-indigo-700"><Plus className="h-4 w-4" /></button>
              </div>
            ))}
          </div>
          <div className="p-4 border-t border-slate-100 flex items-center justify-between gap-3">
            <div className={`text-[12px] ${anyEnabled ? 'text-slate-500' : 'text-rose-500'}`}>{anyEnabled ? 'Default action can now be saved.' : 'Please select the non-working hours first.'}</div>
            <button onClick={save} disabled={!anyEnabled} className={`h-9 px-4 rounded-lg text-[13px] font-semibold ${anyEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-300'}`}>Save</button>
          </div>
        </Card>
        <Card className="p-5 border-dashed min-h-[520px] grid place-items-center">
          {!anyEnabled ? (
            <div className="text-center">
              <div className="h-14 w-14 rounded-full bg-indigo-50 text-indigo-600 grid place-items-center mx-auto"><HelpCircle className="h-7 w-7" /></div>
              <div className="mt-4 text-[15px] font-black text-slate-800">Setup Required</div>
              <div className="mt-2 text-[13px] text-slate-500 max-w-xs">Please select the working time to select the reply material.</div>
            </div>
          ) : (
            <div className="w-full max-w-md">
              <div className="text-[15px] font-black text-slate-900">Reply material</div>
              <select value={marketingDefaultActions.selectedReplyMaterialId || ''} onChange={e => setMarketingDefaultActions(prev => ({ ...prev, selectedReplyMaterialId: e.target.value }))} className="mt-3 w-full h-10 px-3 rounded-lg border border-slate-200 bg-white text-[13px]">
                <option value="">Choose material...</option>
                {marketingReplyMaterials.map(m => <option key={m.id} value={m.id}>{m.title}</option>)}
              </select>
              {selected ? <div className="mt-4 rounded-xl bg-indigo-50 ring-1 ring-indigo-100 p-4 text-[13px] text-slate-700 whitespace-pre-wrap">{selected.body || selected.url || selected.title}</div> : <button onClick={onOpenReplyMaterial} className="mt-4 h-9 px-3 rounded-lg bg-slate-900 text-white text-[12px] font-semibold">Add Reply Material</button>}
            </div>
          )}
        </Card>
      </div>
    </div>
  );
};

const MarketingReplyMaterial_Tab = () => {
  const { marketingReplyMaterials, setMarketingReplyMaterials, toast, confirmAction, viewUser } = useApp();
  const [tab, setTab] = useState('text');
  const [search, setSearch] = useState('');
  const [uploading, setUploading] = useState(false);
  const uploadRef = useRef(null);
  const kinds = [
    { id: 'text', label: 'Text', icon: Type },
    { id: 'video', label: 'Video', icon: Video },
    { id: 'image', label: 'Images', icon: FileUp },
    { id: 'document', label: 'Documents', icon: FileText },
  ];
  const filtered = marketingReplyMaterials.filter(m => m.kind === tab && (!search.trim() || [m.title, m.body, m.url].some(v => String(v || '').toLowerCase().includes(search.trim().toLowerCase()))));
  const addMaterial = () => {
    const label = kinds.find(k => k.id === tab)?.label.replace(/s$/, '') || 'Text';
    setMarketingReplyMaterials(prev => [{ id: 'rm' + Date.now(), kind: tab, title: `${label} reply material`, body: tab === 'text' ? 'Thanks for your message. We will get back to you shortly.' : '', url: '', createdAt: new Date().toISOString() }, ...prev]);
    toast('Reply material added');
  };
  const updateMaterial = (id, patch) => setMarketingReplyMaterials(prev => prev.map(m => m.id === id ? { ...m, ...patch } : m));
  const uploadMaterialFile = async (file) => {
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) { toast('File must be under 50 MB'); return; }
    setUploading(true);
    try {
      const base64 = await fileToBase64(file);
      const kind = (file.type || '').startsWith('image/') ? 'image' : (file.type || '').startsWith('video/') ? 'video' : 'document';
      const response = await fetch(`${API_BASE_URL}/marketing/reply-materials/upload-json`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fileName: file.name,
          displayName: file.name,
          mimeType: file.type || 'application/octet-stream',
          base64,
          materialKind: kind,
          uploadedBy: viewUser?.id || null,
          metadata: { source: 'marketing_reply_material' },
        }),
      });
      const payload = await response.json().catch(() => ({}));
      if (!response.ok || !payload.ok) throw new Error(payload.error || 'Upload failed');
      setMarketingReplyMaterials(prev => [{
        id: 'rm' + Date.now(),
        kind,
        title: payload.file?.display_name || file.name,
        body: '',
        url: payload.url,
        storage: 'supabase',
        storagePath: payload.path,
        fileId: payload.file?.id,
        mimeType: file.type || 'application/octet-stream',
        expiresAt: payload.expiresAt,
        createdAt: new Date().toISOString(),
      }, ...prev]);
      setTab(kind);
      toast('Reply material uploaded to Supabase');
    } catch (error) {
      toast(`Upload failed: ${error.message}`);
    } finally {
      setUploading(false);
      if (uploadRef.current) uploadRef.current.value = '';
    }
  };
  const deleteMaterial = async (m) => {
    const ok = await confirmAction({ title: `Delete "${m.title}"?`, message: 'This removes the reply material from automation pickers.', confirmLabel: 'Delete', danger: true });
    if (!ok) return;
    setMarketingReplyMaterials(prev => prev.filter(x => x.id !== m.id));
    toast('Reply material deleted');
  };

  return (
    <div className="space-y-5">
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div><h1 className="text-[30px] font-black text-slate-900 inline-flex items-center gap-2">Reply Material <HelpCircle className="h-4 w-4 text-slate-400" /></h1><p className="text-[14px] text-slate-500">Reusable text, video, image and document replies for automation.</p></div>
        <div className="flex items-center gap-2 flex-wrap"><div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" /><input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search Text" className="h-10 w-64 pl-9 pr-3 rounded-lg border border-slate-200 bg-white text-[13px]" /></div><button className="h-10 px-3.5 rounded-lg bg-white ring-1 ring-indigo-200 text-indigo-700 text-[13px] font-semibold inline-flex items-center gap-1.5"><PlayCircle className="h-3.5 w-3.5" />Watch Tutorial</button><button onClick={() => uploadRef.current?.click()} disabled={uploading} className="h-10 px-3.5 rounded-lg bg-white ring-1 ring-emerald-200 text-emerald-700 text-[13px] font-semibold inline-flex items-center gap-1.5 disabled:opacity-50"><FileUp className="h-3.5 w-3.5" />{uploading ? 'Uploading' : 'Upload Media'}</button><input ref={uploadRef} type="file" accept="image/*,video/*,application/pdf,.pdf,.doc,.docx,.ppt,.pptx" className="hidden" onChange={e => uploadMaterialFile(e.target.files?.[0])} /><button onClick={addMaterial} className="h-10 px-4 rounded-lg bg-indigo-600 text-white text-[13px] font-semibold">Add {kinds.find(k => k.id === tab)?.label.replace(/s$/, '')}</button></div>
      </div>
      <div className="flex items-center gap-6 border-b border-slate-200">
        {kinds.map(k => {
          const count = marketingReplyMaterials.filter(m => m.kind === k.id).length;
          return <button key={k.id} onClick={() => setTab(k.id)} className={`pb-3 text-[13px] font-semibold inline-flex items-center gap-2 border-b-2 ${tab === k.id ? 'border-indigo-600 text-slate-900' : 'border-transparent text-slate-500'}`}>{k.label}<span className="h-5 min-w-5 px-1.5 rounded-full bg-slate-100 text-slate-500 text-[10px] grid place-items-center">{count}</span></button>;
        })}
      </div>
      <Card className="p-5 min-h-[360px]">
        {filtered.length === 0 ? (
          <div className="h-44 grid place-items-center text-[13px] text-slate-400">No reply material found for this filter.</div>
        ) : (
          <div className="space-y-3">
            {filtered.map(m => (
              <div key={m.id} className="rounded-xl ring-1 ring-slate-200 p-4">
                <div className="grid md:grid-cols-[1fr_1.4fr_1.4fr_auto] gap-3 items-start">
                  <input value={m.title} onChange={e => updateMaterial(m.id, { title: e.target.value })} className="h-10 px-3 rounded-lg border border-slate-200 text-[13px] font-semibold" />
                  <textarea value={m.body || ''} onChange={e => updateMaterial(m.id, { body: e.target.value })} placeholder="Reply text or notes..." rows={2} className="px-3 py-2 rounded-lg border border-slate-200 text-[13px] resize-none" />
                  <div className="space-y-1">
                    <div className="flex gap-2">
                      <input value={m.url || ''} onChange={e => updateMaterial(m.id, { url: e.target.value })} placeholder="https:// file or media link" className="h-10 px-3 rounded-lg border border-slate-200 text-[13px] flex-1" />
                      {m.url && <a href={m.url} target="_blank" rel="noreferrer" className="h-10 w-10 grid place-items-center rounded-lg bg-indigo-50 text-indigo-600"><ExternalLink className="h-4 w-4" /></a>}
                    </div>
                    {m.storage === 'supabase' && <div className="text-[10px] text-emerald-600">Stored in Supabase · signed preview link</div>}
                  </div>
                  <button onClick={() => deleteMaterial(m)} className="h-10 w-10 grid place-items-center rounded-lg text-rose-400 hover:bg-rose-50"><Trash2 className="h-4 w-4" /></button>
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>
  );
};

// ── Reminder Rules tab ──────────────────────────────────────────────────────
const WaReminderRules_Tab = () => {
  const { waRules, setWaRules, waTemplates, toast, confirmAction } = useApp();
  const [editing, setEditing] = useState(null);

  const toggleActive = (id) => setWaRules(waRules.map(r => r.id === id ? { ...r, active: !r.active } : r));
  const onSave = (r) => {
    if (r.id) { setWaRules(waRules.map(x => x.id === r.id ? r : x)); toast('Rule updated'); }
    else { setWaRules([{ ...r, id: 'wr' + Date.now() }, ...waRules]); toast('Rule created'); }
    setEditing(null);
  };
  const onDelete = async (r) => {
    const ok = await confirmAction({ title: `Delete "${r.name}"?`, message: 'This automation will be removed.', confirmLabel: 'Delete', danger: true });
    if (!ok) return;
    setWaRules(waRules.filter(x => x.id !== r.id)); toast('Rule deleted');
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-[20px] font-bold text-slate-900">Reminder Rules</h1>
          <p className="text-[13px] text-slate-500">Automated WhatsApp reminders — trigger, condition, delay, action.</p>
        </div>
        <button onClick={() => setEditing({})} className="h-9 px-3.5 rounded-lg bg-violet-600 text-white text-[13px] font-semibold hover:bg-violet-700 inline-flex items-center gap-1.5"><Plus className="h-3.5 w-3.5" />Create Reminder</button>
      </div>
      <BackendBanner text="Rules are saved here. Actual firing on schedule needs a backend scheduler — once connected, active rules run automatically." />

      <div className="space-y-2">
        {waRules.length === 0 && <div className="rounded-2xl border border-dashed border-slate-200 py-12 text-center text-slate-400 text-[13px]">No reminder rules yet.</div>}
        {waRules.map(r => {
          const trig = WA_TRIGGER_TYPES.find(t => t.id === r.triggerType);
          const tpl = waTemplates.find(t => t.id === r.templateId);
          const rec = WA_RECIPIENT_TYPES.find(t => t.id === r.recipientType);
          return (
            <Card key={r.id} className="p-4">
              <div className="flex items-start gap-3">
                <div className={`h-9 w-9 rounded-lg grid place-items-center shrink-0 ${r.active ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}><AlarmClock className="h-4 w-4" /></div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-[14px] font-semibold text-slate-900">{r.name}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-full ring-1 ${r.active ? 'bg-emerald-50 text-emerald-700 ring-emerald-200' : 'bg-slate-100 text-slate-500 ring-slate-200'}`}>{r.active ? 'Active' : 'Inactive'}</span>
                  </div>
                  <div className="text-[12px] text-slate-500 mt-1.5 flex flex-wrap items-center gap-x-1.5 gap-y-1">
                    <span className="px-1.5 py-0.5 rounded bg-violet-50 text-violet-700 text-[11px] font-medium">{trig?.label || r.triggerType}</span>
                    <ChevronRight className="h-3 w-3 text-slate-300" />
                    <span>{r.condition}</span>
                    <ChevronRight className="h-3 w-3 text-slate-300" />
                    <span className="font-medium text-slate-700">{waDelayLabel(r.delayMinutes)}</span>
                    <ChevronRight className="h-3 w-3 text-slate-300" />
                    <span>WhatsApp → {rec?.label}</span>
                  </div>
                  {tpl && <div className="text-[11px] text-slate-400 mt-1.5 truncate">Template: {tpl.name}</div>}
                </div>
                <div className="flex items-center gap-1 shrink-0">
                  <button onClick={() => toggleActive(r.id)} title={r.active ? 'Pause' : 'Activate'} className={`h-7 px-2 rounded-lg text-[11px] font-medium ${r.active ? 'text-amber-600 hover:bg-amber-50' : 'text-emerald-600 hover:bg-emerald-50'}`}>{r.active ? 'Pause' : 'Activate'}</button>
                  <button onClick={() => setEditing(r)} className="h-7 w-7 grid place-items-center rounded-lg text-slate-400 hover:bg-slate-100"><Pencil className="h-3.5 w-3.5" /></button>
                  <button onClick={() => onDelete(r)} className="h-7 w-7 grid place-items-center rounded-lg text-slate-400 hover:bg-rose-50 hover:text-rose-600"><Trash2 className="h-3.5 w-3.5" /></button>
                </div>
              </div>
            </Card>
          );
        })}
      </div>

      {editing !== null && <WaRuleModal rule={editing} templates={waTemplates} onCancel={() => setEditing(null)} onSave={onSave} />}
    </div>
  );
};

const WaRuleModal = ({ rule, templates, onCancel, onSave }) => {
  const [d, setD] = useState({ name: '', triggerType: 'proposal_sent', condition: '', delayMinutes: 2880, recipientType: 'client', templateId: templates[0]?.id || '', active: true, ...rule });
  const set = (k, v) => setD(p => ({ ...p, [k]: v }));
  const [delayVal, setDelayVal] = useState(() => Math.abs(d.delayMinutes) % 1440 === 0 ? Math.abs(d.delayMinutes) / 1440 : Math.abs(d.delayMinutes) / 60);
  const [delayUnit, setDelayUnit] = useState(() => Math.abs(d.delayMinutes) % 1440 === 0 ? 'days' : 'hours');
  const [delayDir, setDelayDir] = useState(() => d.delayMinutes < 0 ? 'before' : 'after');
  const computeDelay = () => {
    const base = delayUnit === 'days' ? delayVal * 1440 : delayVal * 60;
    return delayDir === 'before' ? -base : base;
  };
  const canSave = d.name.trim() && d.condition.trim();

  return (
    <div className="fixed inset-0 z-[60] flex items-start justify-center p-4 sm:p-6 bg-slate-900/40 backdrop-blur-sm overflow-y-auto" onMouseDown={onCancel}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg my-4" onMouseDown={e => e.stopPropagation()}>
        <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between">
          <div className="inline-flex items-center gap-2 text-[15px] font-bold text-slate-900"><AlarmClock className="h-4 w-4 text-violet-600" />{rule?.id ? 'Edit reminder rule' : 'Create reminder rule'}</div>
          <button onClick={onCancel} className="h-7 w-7 grid place-items-center rounded-lg text-slate-400 hover:bg-slate-100"><X className="h-4 w-4" /></button>
        </div>
        <div className="p-5 space-y-4">
          <Input label="Automation name *" value={d.name} onChange={v => set('name', v)} placeholder="e.g. Proposal follow-up (2 days)" />
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[11px] text-slate-500 font-medium">Trigger type</label>
              <select value={d.triggerType} onChange={e => set('triggerType', e.target.value)} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none">
                {WA_TRIGGER_TYPES.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[11px] text-slate-500 font-medium">Recipient</label>
              <select value={d.recipientType} onChange={e => set('recipientType', e.target.value)} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none">
                {WA_RECIPIENT_TYPES.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
              </select>
            </div>
          </div>
          <Input label="Condition *" value={d.condition} onChange={v => set('condition', v)} placeholder="e.g. Client has not responded" />
          <div>
            <label className="text-[11px] text-slate-500 font-medium">Delay</label>
            <div className="mt-1 flex items-center gap-2">
              <input type="number" min="0" value={delayVal} onChange={e => setDelayVal(Number(e.target.value))} className="w-20 h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] focus:outline-none" />
              <select value={delayUnit} onChange={e => setDelayUnit(e.target.value)} className="h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white"><option value="hours">hours</option><option value="days">days</option></select>
              <select value={delayDir} onChange={e => setDelayDir(e.target.value)} className="h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white"><option value="before">before event</option><option value="after">after event</option></select>
            </div>
          </div>
          <div>
            <label className="text-[11px] text-slate-500 font-medium">Message template</label>
            <select value={d.templateId} onChange={e => set('templateId', e.target.value)} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none">
              {templates.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
            </select>
          </div>
          <label className="flex items-center gap-2 text-[13px] text-slate-700 cursor-pointer">
            <input type="checkbox" checked={d.active} onChange={e => set('active', e.target.checked)} className="rounded border-slate-300 text-violet-600 focus:ring-violet-500" />Active
          </label>
        </div>
        <div className="px-5 py-4 border-t border-slate-100 flex justify-end gap-2">
          <button onClick={onCancel} className="h-9 px-4 rounded-lg text-[13px] font-medium text-slate-600 hover:bg-slate-100">Cancel</button>
          <button disabled={!canSave} onClick={() => onSave({ ...d, delayMinutes: computeDelay() })} className={`h-9 px-4 rounded-lg text-[13px] font-semibold text-white ${canSave ? 'bg-violet-600 hover:bg-violet-700' : 'bg-slate-300 cursor-not-allowed'}`}>{rule?.id ? 'Save' : 'Create'}</button>
        </div>
      </div>
    </div>
  );
};

