const MARKETING_TEMPLATE_STARTER = {
  name: 'Free masterclass invite',
  useCase: 'marketing_campaign',
  status: 'draft',
  headerType: 'image',
  headerImageUrl: '',
  body: `Dear {{client_name}},

I'll keep this quick.

Finalising my new masterclass:
"How to Start & Grow an Interior Design Business"

Before I lock it, your input is needed.
What do you want to learn? (60 secs)

Your answers directly shape the content.
No fluff. Few clicks.`,
  footer: 'SherpaShanker · ArchScale Guild',
  buttons: [
    { id: 'btn_audit', type: 'url', text: 'Book Free Audit', url: 'https://example.com/audit' },
    { id: 'btn_class', type: 'url', text: 'Grab Free Class', url: 'https://example.com/class' },
  ],
};

const TEMPLATE_SAMPLE_VALUES = {
  client_name: 'Ramya',
  assigned_person: 'Devender Singh',
  task_name: 'Review lead list',
  due_date: '5 Jun',
  proposal_name: 'Studio Growth Program',
  project_name: 'Dream Client Framework',
  amount: '₹9,999',
  meeting_time: '4:30 pm',
};

const normalizeWaTemplate = (t = {}) => ({
  id: t.id || '',
  name: t.name || '',
  useCase: t.useCase || 'marketing_campaign',
  status: t.status || 'draft',
  headerType: t.headerType || (t.headerImageUrl ? 'image' : 'none'),
  headerImageUrl: t.headerImageUrl || '',
  body: t.body || '',
  footer: t.footer || '',
  buttons: Array.isArray(t.buttons) ? t.buttons : [],
});

const renderWaTemplateBody = (body = '') => String(body || '').replace(/\{\{\s*([\w_]+)\s*\}\}/g, (_, key) => TEMPLATE_SAMPLE_VALUES[key] || `{{${key}}}`);

const renderWaTemplatePlainText = (template) => {
  const t = normalizeWaTemplate(template);
  const parts = [];
  if (t.headerType === 'image' && t.headerImageUrl) parts.push(`Image: ${t.headerImageUrl}`);
  parts.push(renderWaTemplateBody(t.body));
  if (t.footer) parts.push(t.footer);
  const linkButtons = (t.buttons || []).filter(b => b.text?.trim());
  if (linkButtons.length) {
    parts.push(linkButtons.map((b, i) => {
      const label = `${i + 1}. ${b.text}`;
      return b.type === 'url' && b.url ? `${label}: ${b.url}` : label;
    }).join('\n'));
  }
  return parts.filter(Boolean).join('\n\n');
};

const WaPhonePreview = ({ template }) => {
  const t = normalizeWaTemplate(template);
  const st = WA_TEMPLATE_STATUS[t.status] || WA_TEMPLATE_STATUS.draft;
  return (
    <div className="rounded-[28px] bg-slate-950 p-2 shadow-2xl shadow-slate-900/20 sticky top-20">
      <div className="rounded-[22px] overflow-hidden bg-[#efe7db]">
        <div className="h-11 px-4 bg-white/95 border-b border-slate-200 flex items-center gap-2">
          <div className="h-7 w-7 rounded-full bg-emerald-500 grid place-items-center"><MessageCircle className="h-4 w-4 text-white" /></div>
          <div className="min-w-0">
            <div className="text-[12px] font-bold text-slate-900 truncate">WhatsApp Preview</div>
            <div className="text-[10px] text-emerald-600">template message</div>
          </div>
        </div>
        <div className="min-h-[560px] p-4 flex items-start justify-end">
          <div className="w-full max-w-[330px] rounded-2xl rounded-tr-md bg-[#d9fdd3] shadow-sm overflow-hidden ring-1 ring-emerald-200/50">
            {t.headerType === 'image' && (
              <div className="m-3 mb-2 rounded-xl bg-white/70 min-h-[180px] overflow-hidden grid place-items-center ring-1 ring-emerald-100">
                {t.headerImageUrl ? (
                  <img src={t.headerImageUrl} alt="" className="w-full h-full max-h-[240px] object-cover" />
                ) : (
                  <div className="text-center px-8 py-10">
                    <FileUp className="h-10 w-10 text-emerald-300 mx-auto" />
                    <div className="text-[11px] font-semibold text-emerald-800 mt-2">Header image preview</div>
                    <div className="text-[10px] text-emerald-700/70 mt-1">Paste a hosted image URL in the editor.</div>
                  </div>
                )}
              </div>
            )}
            <div className="px-4 py-3 text-[14px] leading-relaxed text-slate-900 whitespace-pre-wrap">{renderWaTemplateBody(t.body) || 'Write your template body...'}</div>
            {t.footer && <div className="px-4 pb-2 text-[11px] text-slate-500">{t.footer}</div>}
            {(t.buttons || []).filter(b => b.text).length > 0 && (
              <div className="border-t border-emerald-200/70 divide-y divide-emerald-200/70 bg-[#d9fdd3]">
                {t.buttons.filter(b => b.text).slice(0, 3).map(b => (
                  <button key={b.id} className="w-full h-10 px-3 text-[13px] font-semibold text-blue-600 inline-flex items-center justify-center gap-2">
                    {b.type === 'url' ? <Globe className="h-3.5 w-3.5" /> : <MessageSquare className="h-3.5 w-3.5" />}
                    {b.text}
                  </button>
                ))}
              </div>
            )}
            <div className="px-3 pb-2 flex items-center justify-between">
              <span className={`text-[9px] px-1.5 py-0.5 rounded-full ring-1 ${st.tone}`}>{st.label}</span>
              <span className="text-[10px] text-slate-500">08:45</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const WaTemplates_Tab = () => {
  const { waTemplates, setWaTemplates, waConnection, setWaConnection, addWaLog, toast, confirmAction, activeOrganizationId, activeWorkspaceId } = useApp();
  const [selectedId, setSelectedId] = useState(waTemplates[0]?.id || '');
  const [draft, setDraft] = useState(() => normalizeWaTemplate(waTemplates[0] || MARKETING_TEMPLATE_STARTER));
  const [testTo, setTestTo] = useState(() => indianWhatsAppNational(waConnection.testNumber || waConnection.phoneNumber || ''));
  const [sending, setSending] = useState(false);
  const bodyRef = useRef(null);
  const selected = waTemplates.find(t => t.id === selectedId);
  const phoneState = indianWhatsAppState(testTo, false);

  useEffect(() => {
    const next = waTemplates.find(t => t.id === selectedId) || waTemplates[0];
    if (next) {
      setSelectedId(next.id);
      setDraft(normalizeWaTemplate(next));
    }
  }, [selectedId, waTemplates]);

  const saveTemplate = () => {
    const clean = normalizeWaTemplate({ ...draft, buttons: (draft.buttons || []).filter(b => b.text?.trim()).slice(0, 3) });
    if (!clean.name.trim() || !clean.body.trim()) {
      toast('Template name and body are required.');
      return;
    }
    if (clean.id) {
      setWaTemplates(waTemplates.map(t => t.id === clean.id ? clean : t));
      toast('Template saved');
    } else {
      const created = { ...clean, id: 'wt' + Date.now() };
      setWaTemplates([created, ...waTemplates]);
      setSelectedId(created.id);
      toast('Template created');
    }
  };

  const newTemplate = () => {
    setSelectedId('');
    setDraft(normalizeWaTemplate({ ...MARKETING_TEMPLATE_STARTER, id: '', name: 'New WhatsApp template' }));
  };

  const duplicateTemplate = () => {
    const copy = { ...normalizeWaTemplate(draft), id: 'wt' + Date.now(), name: `${draft.name || 'Template'} copy`, status: 'draft' };
    setWaTemplates([copy, ...waTemplates]);
    setSelectedId(copy.id);
    toast('Template duplicated');
  };

  const deleteTemplate = async () => {
    if (!draft.id) return;
    const ok = await confirmAction({ title: `Delete "${draft.name}"?`, message: 'Template will be removed from Marketing and automation pickers.', confirmLabel: 'Delete', danger: true });
    if (!ok) return;
    const remaining = waTemplates.filter(t => t.id !== draft.id);
    setWaTemplates(remaining);
    setSelectedId(remaining[0]?.id || '');
    setDraft(normalizeWaTemplate(remaining[0] || MARKETING_TEMPLATE_STARTER));
    toast('Template deleted');
  };

  const addButton = () => {
    const buttons = [...(draft.buttons || [])];
    if (buttons.length >= 3) {
      toast('WhatsApp supports up to 3 quick action buttons here.');
      return;
    }
    buttons.push({ id: 'btn' + Date.now(), type: 'url', text: '', url: '' });
    setDraft(d => ({ ...d, buttons }));
  };

  const updateButton = (id, patch) => setDraft(d => ({ ...d, buttons: (d.buttons || []).map(b => b.id === id ? { ...b, ...patch } : b) }));
  const removeButton = (id) => setDraft(d => ({ ...d, buttons: (d.buttons || []).filter(b => b.id !== id) }));
  const insertVar = (v) => setDraft(d => ({ ...d, body: `${d.body || ''}${d.body ? ' ' : ''}${v}` }));

  const sendPreview = async () => {
    if (!phoneState.valid || !phoneState.national) {
      toast('Add a valid 10 digit test number first.');
      return;
    }
    setSending(true);
    try {
      const qrSelected = isQrSenderConnection(waConnection);
      const endpoint = qrSelected ? '/wa-web/send' : '/wa/send-test';
      const message = renderWaTemplatePlainText(draft);
      const response = await fetch(`${API_BASE_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: indianWhatsAppSendNumber(testTo),
          message,
          recipient: 'Template studio test',
          relatedModule: 'Marketing template',
          relatedRecordId: draft.id || null,
          organizationId: activeOrganizationId,
          workspaceId: activeWorkspaceId,
        }),
      });
      const payload = await response.json().catch(() => ({}));
      if (!response.ok || !payload.ok) throw new Error(payload.error || 'Template test failed');
      const provider = qrSelected ? 'whatsapp-web' : (payload.result?.provider || payload.provider || 'mock');
      addWaLog({
        recipient: 'Template studio test',
        number: indianWhatsAppSendNumber(testTo),
        type: 'Template preview',
        module: 'Marketing',
        relatedRecordId: draft.id || '',
        sentBy: 'You',
        status: provider === 'mock' ? 'queued' : 'sent',
        msgId: payload.result?.id || payload.log?.provider_message_id || `${provider}_${Date.now()}`,
      });
      setWaConnection({ ...waConnection, testNumber: indianWhatsAppNational(testTo), lastMessageAt: new Date().toISOString(), sentToday: (waConnection.sentToday || 0) + 1 });
      toast(provider === 'mock' ? 'Preview logged in mock mode' : 'Template preview sent');
    } catch (error) {
      addWaLog({
        recipient: 'Template studio test',
        number: indianWhatsAppSendNumber(testTo),
        type: 'Template preview',
        module: 'Marketing',
        relatedRecordId: draft.id || '',
        sentBy: 'You',
        status: 'failed',
        error: error.message,
      });
      toast(`Template test failed: ${error.message}`);
    } finally {
      setSending(false);
    }
  };

  const status = WA_TEMPLATE_STATUS[draft.status] || WA_TEMPLATE_STATUS.draft;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-[22px] font-bold text-slate-900">WhatsApp Template Studio</h1>
          <p className="text-[13px] text-slate-500">Design trusted marketing messages with media headers, variables, footers and action buttons.</p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={newTemplate} className="h-9 px-3.5 rounded-lg bg-violet-600 text-white text-[13px] font-semibold hover:bg-violet-700 inline-flex items-center gap-1.5"><Plus className="h-3.5 w-3.5" />New Template</button>
          <button onClick={saveTemplate} className="h-9 px-3.5 rounded-lg bg-slate-900 text-white text-[13px] font-semibold hover:bg-slate-800 inline-flex items-center gap-1.5"><Save className="h-3.5 w-3.5" />Save</button>
        </div>
      </div>

      <BackendBanner text="QR testing can send this as regular WhatsApp text with links. Native WhatsApp template headers and clickable buttons require Meta Cloud API, WATI, Interakt, or another approved provider later." />

      <div className="grid xl:grid-cols-[320px_minmax(0,1fr)_390px] gap-4 items-start">
        <Card className="overflow-hidden">
          <div className="p-4 border-b border-slate-100 flex items-center justify-between">
            <div>
              <div className="text-[14px] font-bold text-slate-900">Templates</div>
              <div className="text-[11px] text-slate-500">{waTemplates.length} saved</div>
            </div>
            <button onClick={newTemplate} className="h-8 w-8 grid place-items-center rounded-lg bg-violet-50 text-violet-700 hover:bg-violet-100"><Plus className="h-4 w-4" /></button>
          </div>
          <div className="max-h-[720px] overflow-y-auto divide-y divide-slate-100">
            {waTemplates.map(t => {
              const nt = normalizeWaTemplate(t);
              const st = WA_TEMPLATE_STATUS[nt.status] || WA_TEMPLATE_STATUS.draft;
              const isActive = selectedId === nt.id;
              return (
                <button key={nt.id} onClick={() => setSelectedId(nt.id)} className={`w-full text-left p-3 hover:bg-violet-50/50 ${isActive ? 'bg-violet-50' : 'bg-white'}`}>
                  <div className="flex gap-3">
                    <div className="h-12 w-12 rounded-xl bg-slate-100 ring-1 ring-slate-200 overflow-hidden shrink-0 grid place-items-center">
                      {nt.headerImageUrl ? <img src={nt.headerImageUrl} alt="" className="h-full w-full object-cover" /> : <MessageSquare className="h-5 w-5 text-slate-400" />}
                    </div>
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <div className="text-[13px] font-bold text-slate-900 truncate">{nt.name}</div>
                        {isActive && <Check className="h-3.5 w-3.5 text-violet-600 shrink-0" />}
                      </div>
                      <div className="text-[11px] text-slate-500 truncate mt-0.5">{nt.useCase?.replace(/_/g, ' ') || 'marketing'}</div>
                      <div className="mt-2 flex items-center justify-between gap-2">
                        <span className={`text-[10px] px-1.5 py-0.5 rounded-full ring-1 ${st.tone}`}>{st.label}</span>
                        <span className="text-[10px] text-slate-400">{(nt.buttons || []).length} buttons</span>
                      </div>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        </Card>

        <div className="space-y-4">
          <Card className="p-5">
            <div className="flex items-start justify-between gap-3 mb-4">
              <div>
                <div className="text-[16px] font-bold text-slate-900">Template editor</div>
                <div className="text-[12px] text-slate-500">Build the message customers will receive.</div>
              </div>
              <span className={`text-[10px] px-2 py-1 rounded-full ring-1 ${status.tone}`}>{status.label}</span>
            </div>

            <div className="grid md:grid-cols-2 gap-3">
              <Input label="Template name *" value={draft.name} onChange={v => setDraft(d => ({ ...d, name: v }))} placeholder="e.g. Masterclass invite" />
              <div>
                <label className="text-[11px] text-slate-500 font-medium">Status</label>
                <select value={draft.status} onChange={e => setDraft(d => ({ ...d, status: e.target.value }))} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none focus:ring-2 focus:ring-violet-500/30">
                  {Object.entries(WA_TEMPLATE_STATUS).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                </select>
              </div>
              <Input label="Use case / category" value={draft.useCase} onChange={v => setDraft(d => ({ ...d, useCase: v }))} placeholder="marketing_campaign" />
              <div>
                <label className="text-[11px] text-slate-500 font-medium">Header type</label>
                <select value={draft.headerType} onChange={e => setDraft(d => ({ ...d, headerType: e.target.value }))} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none focus:ring-2 focus:ring-violet-500/30">
                  <option value="image">Image header</option>
                  <option value="none">No header</option>
                </select>
              </div>
            </div>

            {draft.headerType === 'image' && (
              <div className="mt-3">
                <Input label="Header image URL" value={draft.headerImageUrl} onChange={v => setDraft(d => ({ ...d, headerImageUrl: v }))} placeholder="https://.../poster.jpg" />
                <div className="text-[10px] text-slate-400 mt-1">Use a public image URL for now. Real upload/storage can be added with Supabase Storage.</div>
              </div>
            )}

            <div className="mt-4">
              <div className="flex items-center justify-between gap-2">
                <label className="text-[11px] text-slate-500 font-medium">Body *</label>
                <DictateTextButton value={draft.body} onChange={value => setDraft(d => ({ ...d, body: value }))} textareaRef={bodyRef} toast={toast} />
              </div>
              <textarea ref={bodyRef} value={draft.body} onChange={e => setDraft(d => ({ ...d, body: e.target.value }))} rows={10} className="mt-1 w-full px-3 py-2 rounded-xl border border-slate-200 text-[14px] leading-relaxed focus:outline-none focus:ring-2 focus:ring-violet-500/30 resize-y" />
              <div className="flex flex-wrap gap-1.5 mt-2">
                {WA_TEMPLATE_VARS.map(v => <button key={v} onClick={() => insertVar(v)} className="px-2 py-1 rounded-lg bg-slate-100 text-slate-600 text-[10px] font-mono hover:bg-violet-100 hover:text-violet-700">{v}</button>)}
              </div>
            </div>

            <div className="mt-4">
              <Input label="Footer" value={draft.footer} onChange={v => setDraft(d => ({ ...d, footer: v }))} placeholder="Brand name or short compliance note" />
            </div>
          </Card>

          <Card className="p-5">
            <div className="flex items-center justify-between gap-3 mb-3">
              <div>
                <div className="text-[15px] font-bold text-slate-900">Buttons</div>
                <div className="text-[12px] text-slate-500">Add up to 3 quick actions.</div>
              </div>
              <button onClick={addButton} className="h-8 px-3 rounded-lg bg-violet-50 text-violet-700 text-[12px] font-semibold hover:bg-violet-100 inline-flex items-center gap-1"><Plus className="h-3 w-3" />Add</button>
            </div>
            <div className="space-y-2">
              {(draft.buttons || []).map((b, idx) => (
                <div key={b.id} className="grid md:grid-cols-[120px_minmax(0,1fr)_minmax(0,1.2fr)_32px] gap-2 items-end rounded-xl bg-slate-50 ring-1 ring-slate-200 p-2.5">
                  <div>
                    <label className="text-[10px] text-slate-500 font-medium">Type</label>
                    <select value={b.type || 'url'} onChange={e => updateButton(b.id, { type: e.target.value })} className="mt-1 w-full h-8 px-2 rounded-lg border border-slate-200 text-[12px] bg-white">
                      <option value="url">URL</option>
                      <option value="quick_reply">Quick reply</option>
                    </select>
                  </div>
                  <div>
                    <label className="text-[10px] text-slate-500 font-medium">Button text</label>
                    <input value={b.text || ''} onChange={e => updateButton(b.id, { text: e.target.value })} placeholder={`Button ${idx + 1}`} className="mt-1 w-full h-8 px-2.5 rounded-lg border border-slate-200 text-[12px]" />
                  </div>
                  <div>
                    <label className="text-[10px] text-slate-500 font-medium">URL</label>
                    <input value={b.url || ''} onChange={e => updateButton(b.id, { url: e.target.value })} disabled={b.type !== 'url'} placeholder="https://..." className="mt-1 w-full h-8 px-2.5 rounded-lg border border-slate-200 text-[12px] disabled:bg-slate-100 disabled:text-slate-400" />
                  </div>
                  <button onClick={() => removeButton(b.id)} className="h-8 w-8 grid place-items-center rounded-lg text-slate-400 hover:text-rose-600 hover:bg-rose-50"><Trash2 className="h-3.5 w-3.5" /></button>
                </div>
              ))}
              {(draft.buttons || []).length === 0 && <div className="rounded-xl border border-dashed border-slate-200 py-6 text-center text-[12px] text-slate-400">No buttons yet.</div>}
            </div>
          </Card>

          <Card className="p-5">
            <div className="flex items-center justify-between flex-wrap gap-3">
              <div>
                <div className="text-[15px] font-bold text-slate-900">Test send</div>
                <div className="text-[12px] text-slate-500">Sends text + links through QR Sender, or logs a mock if provider is not live.</div>
              </div>
              <button disabled={sending || !phoneState.valid || !phoneState.national} onClick={sendPreview} className="h-9 px-4 rounded-lg bg-emerald-600 text-white text-[13px] font-semibold hover:bg-emerald-700 disabled:bg-slate-300 disabled:cursor-not-allowed inline-flex items-center gap-1.5">{sending ? <><Loader2 className="h-3.5 w-3.5 animate-spin" />Sending</> : <><Send className="h-3.5 w-3.5" />Send Preview</>}</button>
            </div>
            <div className="mt-3 grid md:grid-cols-[260px_1fr] gap-3">
              <IndianWhatsAppInput value={testTo} onChange={setTestTo} label="Preview recipient number" />
              <div className="rounded-xl bg-slate-50 ring-1 ring-slate-200 p-3">
                <div className="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Text sent by QR test</div>
                <pre className="mt-2 whitespace-pre-wrap text-[12px] leading-relaxed text-slate-700 font-sans max-h-44 overflow-auto">{renderWaTemplatePlainText(draft)}</pre>
              </div>
            </div>
          </Card>
        </div>

        <div>
          <WaPhonePreview template={draft} />
          <div className="mt-3 flex items-center justify-end gap-2">
            {selected && <button onClick={duplicateTemplate} className="h-8 px-3 rounded-lg bg-white ring-1 ring-slate-200 text-slate-600 text-[12px] font-semibold hover:bg-slate-50 inline-flex items-center gap-1"><Copy className="h-3 w-3" />Duplicate</button>}
            {draft.id && <button onClick={deleteTemplate} className="h-8 px-3 rounded-lg bg-white ring-1 ring-rose-200 text-rose-600 text-[12px] font-semibold hover:bg-rose-50 inline-flex items-center gap-1"><Trash2 className="h-3 w-3" />Delete</button>}
          </div>
        </div>
      </div>
    </div>
  );
};

const WaTemplateModal = ({ tpl, onCancel, onSave }) => {
  const { toast } = useApp();
  const [d, setD] = useState({ name: '', useCase: 'proposal_sent', status: 'draft', body: '', ...tpl });
  const set = (k, v) => setD(p => ({ ...p, [k]: v }));
  const bodyRef = useRef(null);
  const insertVar = (v) => set('body', (d.body || '') + ' ' + v);
  const canSave = d.name.trim() && d.body.trim();
  return (
    <div className="fixed inset-0 z-[60] flex items-start justify-center p-4 sm:p-6 bg-slate-900/40 backdrop-blur-sm overflow-y-auto" onMouseDown={onCancel}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg my-4" onMouseDown={e => e.stopPropagation()}>
        <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between">
          <div className="inline-flex items-center gap-2 text-[15px] font-bold text-slate-900"><MessageSquare className="h-4 w-4 text-violet-600" />{tpl?.id ? 'Edit template' : 'New template'}</div>
          <button onClick={onCancel} className="h-7 w-7 grid place-items-center rounded-lg text-slate-400 hover:bg-slate-100"><X className="h-4 w-4" /></button>
        </div>
        <div className="p-5 space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <Input label="Template name *" value={d.name} onChange={v => set('name', v)} />
            <div>
              <label className="text-[11px] text-slate-500 font-medium">Status</label>
              <select value={d.status} onChange={e => set('status', e.target.value)} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none">
                {Object.entries(WA_TEMPLATE_STATUS).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
              </select>
            </div>
          </div>
          <div>
            <label className="text-[11px] text-slate-500 font-medium">Use case</label>
            <select value={d.useCase} onChange={e => set('useCase', e.target.value)} className="mt-1 w-full h-9 px-2.5 rounded-lg border border-slate-200 text-[13px] bg-white focus:outline-none">
              {WA_TRIGGER_TYPES.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
            </select>
          </div>
          <div>
            <div className="flex items-center justify-between gap-2">
              <label className="text-[11px] text-slate-500 font-medium">Message body *</label>
              <DictateTextButton value={d.body} onChange={value => set('body', value)} textareaRef={bodyRef} toast={toast} />
            </div>
            <textarea ref={bodyRef} value={d.body} onChange={e => set('body', e.target.value)} rows={4} className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-[14px] focus:outline-none focus:ring-2 focus:ring-violet-500/30 resize-none" />
            <div className="flex flex-wrap gap-1 mt-2">
              {WA_TEMPLATE_VARS.map(v => <button key={v} onClick={() => insertVar(v)} className="px-2 py-0.5 rounded bg-slate-100 text-slate-600 text-[10px] font-mono hover:bg-violet-100 hover:text-violet-700">{v}</button>)}
            </div>
          </div>
        </div>
        <div className="px-5 py-4 border-t border-slate-100 flex justify-end gap-2">
          <button onClick={onCancel} className="h-9 px-4 rounded-lg text-[13px] font-medium text-slate-600 hover:bg-slate-100">Cancel</button>
          <button disabled={!canSave} onClick={() => onSave(d)} className={`h-9 px-4 rounded-lg text-[13px] font-semibold text-white ${canSave ? 'bg-violet-600 hover:bg-violet-700' : 'bg-slate-300 cursor-not-allowed'}`}>{tpl?.id ? 'Save' : 'Create'}</button>
        </div>
      </div>
    </div>
  );
};

// ── Logs tab ────────────────────────────────────────────────────────────────
const WaLogs_Tab = () => {
  const { waLogs, setWaLogs, toast } = useApp();
  const [filter, setFilter] = useState('all');
  const filtered = filter === 'all' ? waLogs : waLogs.filter(l => l.status === filter);
  const retry = (id) => { setWaLogs(waLogs.map(l => l.id === id ? { ...l, status: 'sent', error: '', msgId: 'wamid.RT' + Date.now().toString().slice(-5) } : l)); toast('Retried — message re-queued'); };
  const stats = {
    total: waLogs.length,
    delivered: waLogs.filter(l => ['delivered','read','sent'].includes(l.status)).length,
    read: waLogs.filter(l => l.status === 'read').length,
    failed: waLogs.filter(l => l.status === 'failed').length,
  };
  return (
    <div className="space-y-4">
      <div>
        <h1 className="text-[20px] font-bold text-slate-900">Message Logs</h1>
        <p className="text-[13px] text-slate-500">Delivery history across all WhatsApp automations.</p>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card className="p-4"><div className="text-[22px] font-bold text-slate-900 tabular-nums">{stats.total}</div><div className="text-[11px] text-slate-500 mt-1">Total</div></Card>
        <Card className="p-4"><div className="text-[22px] font-bold text-emerald-700 tabular-nums">{stats.delivered}</div><div className="text-[11px] text-slate-500 mt-1">Delivered</div></Card>
        <Card className="p-4"><div className="text-[22px] font-bold text-violet-700 tabular-nums">{stats.read}</div><div className="text-[11px] text-slate-500 mt-1">Read</div></Card>
        <Card className="p-4"><div className="text-[22px] font-bold text-rose-700 tabular-nums">{stats.failed}</div><div className="text-[11px] text-slate-500 mt-1">Failed</div></Card>
      </div>
      <Card className="overflow-hidden">
        <div className="px-4 py-3 border-b border-slate-100 flex items-center gap-2 flex-wrap">
          <div className="text-[14px] font-semibold text-slate-900">Recent messages</div>
          <div className="ml-auto flex items-center gap-1 p-1 rounded-lg bg-slate-100">
            {['all','delivered','read','failed'].map(f => (
              <button key={f} onClick={() => setFilter(f)} className={`px-2.5 py-1 rounded-md text-[12px] font-medium capitalize ${filter === f ? 'bg-white shadow-sm text-slate-900' : 'text-slate-600 hover:text-slate-900'}`}>{f}</button>
            ))}
          </div>
        </div>
        <div className="divide-y divide-slate-100">
          {filtered.map(l => {
            const st = WA_LOG_STATUS[l.status] || WA_LOG_STATUS.queued;
            return (
              <div key={l.id} className="px-4 py-3 flex items-center gap-3">
                <span className={`h-2 w-2 rounded-full shrink-0 ${st.dot}`} />
                <div className="flex-1 min-w-0">
                  <div className="text-[13px] font-medium text-slate-800 truncate">{l.type} <span className="text-slate-400">·</span> <span className="text-slate-500 font-normal">{l.module}</span></div>
                  <div className="text-[11px] text-slate-500 mt-0.5 truncate">To {l.recipient} · {l.number} · {l.at} {l.sentBy && `· by ${l.sentBy}`}</div>
                  {l.error && <div className="text-[11px] text-rose-600 mt-0.5">{l.error}</div>}
                </div>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-full ring-1 shrink-0 ${st.tone}`}>{st.label}</span>
                {l.status === 'failed' && <button onClick={() => retry(l.id)} className="h-7 px-2.5 rounded-lg text-[11px] font-medium text-violet-700 hover:bg-violet-50 inline-flex items-center gap-1 shrink-0"><RotateCw className="h-3 w-3" />Retry</button>}
              </div>
            );
          })}
          {filtered.length === 0 && <div className="px-4 py-10 text-center text-slate-400 text-[13px]">No messages match.</div>}
        </div>
      </Card>
    </div>
  );
};

