  const [confirmState, setConfirmState] = useState(null);
  // Tasks: load + retro-number any task without `num` in chronological order; persist a monotonic `taskSeq` counter.
  const [tasks, setTasks] = useState(() => {
    const base = saved?.tasks ?? INITIAL_TASKS;
    // Sort missing-num tasks by creation time (parsed from 't<timestamp>' id) ascending — earliest gets the lowest number.
    const parseCreated = (t) => {
      const m = String(t.id || '').match(/^t(\d+)$/);
      return m ? parseInt(m[1], 10) : 0;
    };
    let maxNum = base.reduce((m, t) => Math.max(m, t.num || 0), 0);
    const missing = base.filter(t => !t.num).sort((a, b) => parseCreated(a) - parseCreated(b));
    const numMap = new Map();
    missing.forEach(t => { maxNum += 1; numMap.set(t.id, maxNum); });
    return base.map(t => t.num ? t : { ...t, num: numMap.get(t.id) });
  });
  const [taskSeq, setTaskSeq] = useState(() => {
    const base = saved?.tasks ?? INITIAL_TASKS;
    const maxFromTasks = base.reduce((m, t) => Math.max(m, t.num || 0), 0);
    return Math.max(saved?.taskSeq || 0, maxFromTasks);
  });
