    setDrawer({ open: true, mode: 'create', taskId: null, prefill: { title: idea.title, dept: idea.dept, notes: idea.notes, priority: idea.impact === 'high' ? 'high' : idea.impact === 'low' ? 'low' : 'med', assignedTo: idea.owner } });
